import type {StickerPlacement} from "@birthday/shared";
import {
    pointInPoly,
    pointInRotatedRect,
    isPointerOutsideRect,
    isPositionOutsideCanvas,
    distance,
    centroid,
    pinchDistance,
    pinchAngle,
    pinchMidpoint,
    applyPinchToBaseline,
    clampGroupScaleFactor,
} from '../geometry-helpers';

// ── Types ────────────────────────────────────────────────────────────────────

export interface ActivePointer {
  id: number;
  x: number;
  y: number;
}

export interface GroupBaseline {
  instanceId: string;
  baseX: number;
  baseY: number;
  baseScale: number;
  baseRotation: number;
  relCx: number;
  relCy: number;
}

export interface MoveBaseline {
  instanceId: string;
  baseX: number;
  baseY: number;
}

export type GestureCallbacks = {
  onPlacementsChanged: (placements: StickerPlacement[]) => void;
  onLassoPathChanged: (path: { x: number; y: number }[] | null) => void;
  onLassoSelectionChanged: (ids: Set<string>) => void;
  onSelectedChanged: (instanceId: string | null) => void;
  onStickerDraggedOff?: (id: string, allIds: string[]) => void;
  onDragNearEdge?: (outsideCanvas: boolean) => void;
  onPointerUpCommit?: () => void;
  onMoveActiveChanged?: (active: boolean) => void;
  onDoubleTap?: (ids: string[]) => void;
  /** Returns the current selection's bounding box (canvas-local) + rotation, or null. */
  getSelectionBounds?: () => { box: { x: number; y: number; w: number; h: number }; rotation: number } | null;
};


// ── GestureHandler ───────────────────────────────────────────────────────────
export class StickerGestureHandler {
  private pointers: ActivePointer[] = [];


  // Freehand lasso state
  private lassoActive = false;
  private lassoPath: { x: number; y: number }[] = [];

  // Move state
  private moveActive = false;
  private moveOffsetX = 0;
  private moveOffsetY = 0;
  private moveBaselines: MoveBaseline[] = [];
  private didMove = false;

  // Pinch state
  private pinchBaseDistance = 0;
  private pinchBaseAngle = 0;
  private pinchBaselines: GroupBaseline[] = [];

  // Tap detection
  private tapStartX = 0;
  private tapStartY = 0;
  private tapMoved = false;

  // Double-tap detection
  private lastTapTime = 0;
  private lastTapX = 0;
  private lastTapY = 0;

  // Snapshot
  private stickers: StickerPlacement[] = [];
  private selectedInstanceId: string | null = null;
  private lassoSelection: Set<string> = new Set();

  constructor(
    private readonly getCanvasRect: () => DOMRect,
    private readonly hitTest: (clientX: number, clientY: number) => string | null,
    private readonly callbacks: GestureCallbacks,
  ) {
  }

  public syncState(
    stickers: StickerPlacement[],
    selectedInstanceId: string | null,
    lassoSelection: Set<string>,
  ): void {
    this.stickers = stickers;
    this.selectedInstanceId = selectedInstanceId;
    this.lassoSelection = lassoSelection;
  }


  // ── Pointer events ────────────────────────────────────────────────────────

  public onPointerDown(id: number, clientX: number, clientY: number): void {
    this.pointers.push({id, x: clientX, y: clientY});

    // Second finger → upgrade to pinch
    if (this.pointers.length === 2) {
      this.tapMoved = true;
      this.lassoActive = false;
      this.lassoPath = [];
      this.callbacks.onLassoPathChanged(null);
      this.moveActive = false;
      const ids = this.currentSelectionIds();
      if (ids.length > 0) this.initPinch(ids);
      return;
    }

    // First finger
    this.tapStartX = clientX;
    this.tapStartY = clientY;
    this.tapMoved = false;
    this.didMove = false;

    const rect = this.getCanvasRect();
    const localX = clientX - rect.left;
    const localY = clientY - rect.top;
    const hitId = this.hitTest(clientX, clientY);

    if (this.hasSelection()) {
      // If the tap lands inside the selection's bounding box, drag it —
      // regardless of whether a sticker hitbox was actually hit.
      // This makes small stickers and groups much easier to move.
      const selBounds = this.callbacks.getSelectionBounds?.();
      const inBounds = selBounds
        ? pointInRotatedRect(localX, localY, selBounds.box, selBounds.rotation, 8)
        : false;

      if (inBounds) {
        // Inside the overlay → move current selection
        this.startMove(localX, localY);
      } else if (!hitId) {
        // Outside bounds, no hitbox hit → deselect + start lasso
        this.selectedInstanceId = null;
        this.lassoSelection = new Set();
        this.callbacks.onSelectedChanged(null);
        this.callbacks.onLassoSelectionChanged(new Set());
        this.lassoActive = true;
        this.lassoPath = [{x: localX, y: localY}];
        this.callbacks.onLassoPathChanged(this.lassoPath);
      } else if (!this.isSelected(hitId)) {
        // Hit a different sticker outside the selection → switch to it
        this.selectAndMove(hitId, localX, localY);
      } else {
        // Hit an already-selected sticker → move
        this.startMove(localX, localY);
      }
    } else if (hitId) {
      this.selectAndMove(hitId, localX, localY);
    } else {
      // Empty area → freehand lasso
      this.lassoActive = true;
      this.lassoPath = [{x: localX, y: localY}];
      this.callbacks.onLassoPathChanged(this.lassoPath);
    }
  }

  public onPointerMove(id: number, clientX: number, clientY: number): void {
    const idx = this.pointers.findIndex(p => p.id === id);
    if (idx < 0) return;
    this.pointers[idx] = {id, x: clientX, y: clientY};

    if (!this.tapMoved && Math.hypot(clientX - this.tapStartX, clientY - this.tapStartY) > 6)
      this.tapMoved = true;

    const rect = this.getCanvasRect();
    const localX = clientX - rect.left;
    const localY = clientY - rect.top;

    if (this.pointers.length === 2 && this.pinchBaselines.length > 0) {
      this.applyPinch();
      this.didMove = true;
      return;
    }

    if (this.moveActive && this.pointers.length === 1) {
      const dx = localX - this.moveOffsetX;
      const dy = localY - this.moveOffsetY;
      const updated = this.stickers.map(p => {
        const b = this.moveBaselines.find(b => b.instanceId === p.instanceId);
        return b ? {...p, x: b.baseX + dx, y: b.baseY + dy} : p;
      });
      this.callbacks.onPlacementsChanged(updated);
      this.didMove = true;
      if (this.callbacks.onDragNearEdge && this.hasSelection()) {
        this.callbacks.onDragNearEdge(
          this.isPointerOrCentroidNotOnCanvas(clientX, clientY, rect, updated),
        );
      }
      return;
    }

    if (this.lassoActive && this.pointers.length === 1) {
      const last = this.lassoPath[this.lassoPath.length - 1];
      if (!last || distance(localX, localY, last.x, last.y) > 2) {
        this.lassoPath.push({x: localX, y: localY});
        this.callbacks.onLassoPathChanged([...this.lassoPath]);
      }
    }
  }

  public onPointerUp(id: number, clientX: number, clientY: number): void {
    this.pointers = this.pointers.filter(p => p.id !== id);

    if (this.pointers.length === 0) {

      if (this.moveActive && this.tapMoved && this.callbacks.onStickerDraggedOff) {
        const rect = this.getCanvasRect();
        // Compute final placements with the current move offsets
        // (this.stickers may be stale — syncState hasn't run yet)
        const localX = clientX - rect.left;
        const localY = clientY - rect.top;
        const dx = localX - this.moveOffsetX;
        const dy = localY - this.moveOffsetY;
        const finalPlacements = this.stickers.map(p => {
          const b = this.moveBaselines.find(b => b.instanceId === p.instanceId);
          return b ? {...p, x: b.baseX + dx, y: b.baseY + dy} : p;
        });
        const outside = this.isPointerOrCentroidNotOnCanvas(clientX, clientY, rect, finalPlacements);
        if (outside && this.hasSelection()) {
          const ids = this.currentSelectionIds();
          this.selectedInstanceId = null;
          this.lassoSelection = new Set();
          this.moveActive = false;
          this.moveBaselines = [];
          this.callbacks.onMoveActiveChanged?.(false);
          this.callbacks.onSelectedChanged(null);
          this.callbacks.onLassoSelectionChanged(new Set());
          this.callbacks.onDragNearEdge?.(false);
          this.callbacks.onStickerDraggedOff(ids[0], ids);
          return;
        }
      }

      if (this.didMove) {
        this.callbacks.onPointerUpCommit?.();
      }
      this.finaliseLasso();
      this.moveActive = false;
      this.moveBaselines = [];
      this.pinchBaselines = [];
      this.didMove = false;
      this.callbacks.onMoveActiveChanged?.(false);
      this.callbacks.onDragNearEdge?.(false);

      // Double-tap detection
      if (!this.tapMoved && this.hasSelection()) {
        const now = Date.now();
        const dist = distance(clientX, clientY, this.lastTapX, this.lastTapY);
        if (now - this.lastTapTime < 350 && dist < 30) {
          this.callbacks.onDoubleTap?.(this.currentSelectionIds());
          this.lastTapTime = 0; // reset so triple-tap doesn't fire again
        } else {
          this.lastTapTime = now;
          this.lastTapX = clientX;
          this.lastTapY = clientY;
        }
      }
    }

    // Re-anchor when going 2 → 1 finger
    if (this.pointers.length === 1 && this.moveActive) {
      const remaining = this.pointers[0];
      const rect = this.getCanvasRect();
      this.moveOffsetX = remaining.x - rect.left;
      this.moveOffsetY = remaining.y - rect.top;
      this.moveBaselines = this.selectedStickers()
        .map(p => ({instanceId: p.instanceId, baseX: p.x, baseY: p.y}));
      this.pinchBaselines = [];
    }
  }

  // ── Private helpers ───────────────────────────────────────────────────────

  private hasSelection(): boolean {
    return !!this.selectedInstanceId || this.lassoSelection.size > 0;
  }

  /**
   * Returns true if the pointer OR the centroid of the selected stickers
   * is outside the canvas bounds. This allows stickers to be deleted when
   * they're dragged to the edge even if the pointer is still barely inside.
   */
  private isPointerOrCentroidNotOnCanvas(clientX: number, clientY: number, rect: DOMRect, placements?: StickerPlacement[]): boolean {
    if (isPointerOutsideRect(clientX, clientY, rect)) return true;

    const source = placements ?? this.stickers;
    const sel = source.filter(p => this.isSelected(p.instanceId));
    if (sel.length === 0) return false;
    const c = centroid(sel);
    return isPositionOutsideCanvas(c.x, c.y, rect);
  }

  private isSelected(id: string): boolean {
    return this.selectedInstanceId === id || this.lassoSelection.has(id);
  }

  private currentSelectionIds(): string[] {
    if (this.lassoSelection.size > 0) return [...this.lassoSelection];
    return this.selectedInstanceId ? [this.selectedInstanceId] : [];
  }

  private selectedStickers(): StickerPlacement[] {
    return this.stickers.filter(p => this.isSelected(p.instanceId));
  }

  // Returns all instanceIds for the same group if hit sticker belongs to one,
  // otherwise just [hitId].
  private resolveHit(hitId: string): string[] {
    const hit = this.stickers.find(p => p.instanceId === hitId);
    if (hit?.groupId) {
      return this.stickers
        .filter(p => p.groupId === hit.groupId)
        .map(p => p.instanceId);
    }
    return [hitId];
  }

  private selectAndMove(hitId: string, localX: number, localY: number): void {
    const ids = this.resolveHit(hitId);
    if (ids.length > 1) {
      const groupSet = new Set(ids);
      this.lassoSelection = groupSet;
      this.selectedInstanceId = null;
      // Emit lasso first; do NOT call onSelectedChanged(null) afterwards —
      // that would trigger clearSelection() in the canvas and wipe the lasso set.
      this.callbacks.onLassoSelectionChanged(groupSet);
    } else {
      this.selectedInstanceId = hitId;
      this.lassoSelection = new Set();
      this.callbacks.onSelectedChanged(hitId);
      this.callbacks.onLassoSelectionChanged(new Set());
    }
    this.startMove(localX, localY);
  }

  private startMove(localX: number, localY: number): void {
    this.moveActive = true;
    this.moveOffsetX = localX;
    this.moveOffsetY = localY;
    this.moveBaselines = this.selectedStickers()
      .map(p => ({instanceId: p.instanceId, baseX: p.x, baseY: p.y}));
  }

  private finaliseLasso(): void {
    if (!this.lassoActive) return;
    this.lassoActive = false;
    this.callbacks.onLassoPathChanged(null);

    const path = this.lassoPath;
    this.lassoPath = [];

    if (path.length < 2) return;

    // Build closed polygon — if only 2 points, expand to a rect
    let poly: { x: number; y: number }[];
    if (path.length === 2) {
      const [a, b] = path;
      poly = [
        {x: a.x, y: a.y}, {x: b.x, y: a.y},
        {x: b.x, y: b.y}, {x: a.x, y: b.y},
        {x: a.x, y: a.y},
      ];
    } else {
      poly = [...path, path[0]];
    }

    const captured = this.stickers.filter(p => pointInPoly(p.x, p.y, poly));

    if (captured.length > 1) {
      // First clear single selection, then set the lasso group
      this.callbacks.onSelectedChanged(null);
      this.callbacks.onLassoSelectionChanged(new Set(captured.map(p => p.instanceId)));
    } else if (captured.length === 1) {
      this.callbacks.onLassoSelectionChanged(new Set());
      this.callbacks.onSelectedChanged(captured[0].instanceId);
    }
  }

  private initPinch(ids: string[]): void {
    if (this.pointers.length < 2) return;
    const [a, b] = this.pointers;
    const pp = {ax: a.x, ay: a.y, bx: b.x, by: b.y};
    const rect = this.getCanvasRect();
    this.pinchBaseDistance = pinchDistance(pp);
    this.pinchBaseAngle = pinchAngle(pp);
    const mid = pinchMidpoint(pp, rect);
    this.pinchBaselines = ids
      .map(iid => this.stickers.find(p => p.instanceId === iid))
      .filter((p): p is StickerPlacement => !!p)
      .map(p => ({
        instanceId: p.instanceId,
        baseX: p.x,
        baseY: p.y,
        baseScale: p.scale,
        baseRotation: p.rotation,
        relCx: p.x - mid.x,
        relCy: p.y - mid.y,
      }));
  }

  private applyPinch(): void {
    if (this.pointers.length < 2 || !this.pinchBaselines.length) return;
    const [a, b] = this.pointers;
    const pp = {ax: a.x, ay: a.y, bx: b.x, by: b.y};
    const mid = pinchMidpoint(pp, this.getCanvasRect());
    const rawFactor = pinchDistance(pp) / this.pinchBaseDistance;
    const factor = clampGroupScaleFactor(rawFactor, this.pinchBaselines.map(bl => bl.baseScale));
    this.callbacks.onPlacementsChanged(
      this.stickers.map(p => {
        const base = this.pinchBaselines.find(b => b.instanceId === p.instanceId);
        if (!base) return p;
        const result = applyPinchToBaseline(base, this.pinchBaseAngle, factor, pp, mid);
        return {...p, ...result};
      }),
    );
  }
}

import {
  AfterViewInit,
  Directive,
  ElementRef,
  Input,
  OnChanges,
  OnInit,
  Optional,
  SimpleChanges,
  SkipSelf,
} from "@angular/core";
import gsap from "gsap";

export type AnimType = "opacity" | "banner" | "strip" | "players" | "medal" | "choice" | "overlay";

interface AnimPreset {
  from: gsap.TweenVars;
  to: gsap.TweenVars;
}

const PRESETS: Record<AnimType, AnimPreset> = {
  opacity: {from: {opacity: 0}, to: {opacity: 1, duration: 0.3, ease: "power2.out"}},
  banner: {from: {opacity: 0, y: -24}, to: {opacity: 1, y: 0, duration: 0.45, ease: "power2.out"}},
  strip: {from: {opacity: 0, x: 60}, to: {opacity: 1, x: 0, duration: 0.55, ease: "power2.out"}},
  players: {from: {opacity: 0, scale: 0.95}, to: {opacity: 1, scale: 1, duration: 0.4, ease: "power2.out"}},
  medal: {from: {opacity: 0, scale: 0.5}, to: {opacity: 1, scale: 1, duration: 0.5, ease: "back.out(1.7)"}},
  choice: {from: {opacity: 0, x: -15}, to: {opacity: 1, x: 0, duration: 0.3, ease: "power2.out"}},
  overlay: {from: {opacity: 0}, to: {opacity: 1, duration: 0.2, ease: "power1.out"}},
};

// ─── Container für gestaggerte Gruppen ───────────────────────────────────────
// Defined first so AnimOnInitDirective can reference AnimGroupDirective.isDone.

@Directive({selector: "[animGroup]", standalone: true})
export class AnimGroupDirective implements AfterViewInit {
  @Input("animGroup") public animType: AnimType = "opacity";
  @Input() public animStagger = 0.08;
  @Input() public animDelay = 0;

  /** True once the group's stagger animation has completed (or had nothing to animate). */
  public isDone = false;
  private readonly children: AnimOnInitDirective[] = [];

  public register(child: AnimOnInitDirective): void {
    this.children.push(child);
  }

  public ngAfterViewInit(): void {
    const matching = this.children.filter(c => c.animType === this.animType);
    if (matching.length === 0) {
      this.isDone = true;
      return;
    }
    const elements = matching.map(c => c.el.nativeElement);
    const preset = PRESETS[this.animType] ?? PRESETS.opacity;
    gsap.fromTo(elements, preset.from, {
      ...preset.to,
      stagger: this.animStagger,
      delay: this.animDelay,
      onComplete: () => {
        this.isDone = true;
      },
    });
  }
}

// ─── Einzelnes Element ────────────────────────────────────────────────────────

@Directive({
  selector: "[animOnInit]",
  standalone: true,
  host: {style: "opacity: 0"},
})
export class AnimOnInitDirective implements OnInit, AfterViewInit {
  @Input("animOnInit") public animType: AnimType = "opacity";
  @Input() public animDelay = 0;

  public constructor(
    public readonly el: ElementRef<HTMLElement>,
    @Optional() @SkipSelf() private readonly group: AnimGroupDirective | null,
  ) {
  }

  public ngOnInit(): void {
    gsap.set(this.el.nativeElement, PRESETS[this.animType]?.from ?? PRESETS.opacity.from);
    this.group?.register(this);
  }

  public ngAfterViewInit(): void {
    // Delegate to the group only if the group animation hasn't finished yet
    // (i.e. we were present at mount time). If isDone is true, we were inserted
    // dynamically via @if after mount — animate ourselves independently.
    if (this.group?.animType === this.animType && !this.group.isDone) return;

    const preset = PRESETS[this.animType] ?? PRESETS.opacity;
    gsap.fromTo(this.el.nativeElement, preset.from, {
      ...preset.to,
      delay: (preset.to["delay"] as number ?? 0) + this.animDelay,
    });
  }
}

// ─── Präsenz-Animation (Ein-/Ausblenden) ─────────────────────────────────────

@Directive({
  selector: "[animPresence]",
  standalone: true,
})
export class AnimPresenceDirective implements OnInit, OnChanges {
  @Input("animPresence") public visible = false;
  @Input() public animPresenceType: AnimType = "opacity";
  @Input() public animPresenceDelay = 0;

  public constructor(private readonly el: ElementRef<HTMLElement>) {}

  public ngOnInit(): void {
    if (this.visible) {
      this.showImmediately();
      return;
    }
    this.hideImmediately();
  }

  public ngOnChanges(changes: SimpleChanges): void {
    if (!changes["visible"] || changes["visible"].firstChange) return;
    if (this.visible) {
      this.animateIn();
      return;
    }
    this.animateOut();
  }

  private animateIn(): void {
    const node = this.el.nativeElement;
    const preset = PRESETS[this.animPresenceType] ?? PRESETS.opacity;
    gsap.killTweensOf(node);
    node.style.display = "";
    node.style.visibility = "visible";
    node.style.pointerEvents = "";

    gsap.fromTo(node, preset.from, {
      ...preset.to,
      delay: (preset.to["delay"] as number ?? 0) + this.animPresenceDelay,
      clearProps: "transform,opacity",
    });
  }

  private animateOut(): void {
    const node = this.el.nativeElement;
    const preset = PRESETS[this.animPresenceType] ?? PRESETS.opacity;
    const duration = Math.max(0.16, Number(preset.to["duration"] ?? 0.2) * 0.85);
    gsap.killTweensOf(node);

    gsap.to(node, {
      opacity: 0,
      x: (preset.from["x"] as number | undefined) ?? 0,
      y: (preset.from["y"] as number | undefined) ?? 0,
      scale: (preset.from["scale"] as number | undefined) ?? 1,
      duration,
      ease: "power1.in",
      onComplete: () => this.hideImmediately(),
    });
  }

  private showImmediately(): void {
    const node = this.el.nativeElement;
    gsap.killTweensOf(node);
    node.style.display = "";
    node.style.visibility = "visible";
    node.style.pointerEvents = "";
  }

  private hideImmediately(): void {
    const node = this.el.nativeElement;
    gsap.killTweensOf(node);
    node.style.display = "none";
    node.style.visibility = "hidden";
    node.style.pointerEvents = "none";
    gsap.set(node, {clearProps: "transform,opacity"});
  }
}

export interface BoundingBox {
    x: number;
    y: number;
    w: number;
    h: number;
}

/** Initial rendered height of a sticker on the canvas — matches the CSS class on the sticker element. */
export const CANVAS_STICKER_PX = 200;

import {BoundingBox} from './sticker-types';
import {degToRad, rotatePt} from './geometry-helpers';

export interface CornerHandles {
    /** Top-left corner (after rotation). */
    tl: { x: number; y: number };
    /** Top-right corner (after rotation). */
    tr: { x: number; y: number };
    /** Bottom-right corner (after rotation). */
    br: { x: number; y: number };
    /** Bottom-left corner (after rotation). */
    bl: { x: number; y: number };
}

/**
 * All geometric information about the current selection:
 * the axis-aligned bounding box (in canvas coords), the rotation angle,
 * and the four corner handle positions already rotated around the box centre.
 */
export class SelectionInfo {
    readonly box: BoundingBox;
    readonly rotation: number;
    readonly corners: CornerHandles;

    constructor(box: BoundingBox, rotation: number) {
        this.box = box;
        this.rotation = rotation;
        this.corners = SelectionInfo.computeCorners(box, rotation);
    }

    private static computeCorners(box: BoundingBox, rotation: number): CornerHandles {
        const {x, y, w, h} = box;
        const cx = x + w / 2;
        const cy = y + h / 2;
        const rad = degToRad(rotation);
        return {
            tl: rotatePt(x,     y,     cx, cy, rad),
            tr: rotatePt(x + w, y,     cx, cy, rad),
            br: rotatePt(x + w, y + h, cx, cy, rad),
            bl: rotatePt(x,     y + h, cx, cy, rad),
        };
    }
}

import type {StickerPlacement} from "@birthday/shared";
import {
    pointInPoly,
    pointInRotatedRect,
    isPointerOutsideRect,
    isPositionOutsideCanvas,
    distance,
    centroid,
    pinchDistance,
    pinchAngle,
    pinchMidpoint,
    applyPinchToBaseline,
    clampGroupScaleFactor,
} from '../geometry-helpers';

// ── Types ────────────────────────────────────────────────────────────────────

export interface ActivePointer {
  id: number;
  x: number;
  y: number;
}

export interface GroupBaseline {
  instanceId: string;
  baseX: number;
  baseY: number;
  baseScale: number;
  baseRotation: number;
  relCx: number;
  relCy: number;
}

export interface MoveBaseline {
  instanceId: string;
  baseX: number;
  baseY: number;
}

export type GestureCallbacks = {
  onPlacementsChanged: (placements: StickerPlacement[]) => void;
  onLassoPathChanged: (path: { x: number; y: number }[] | null) => void;
  onLassoSelectionChanged: (ids: Set<string>) => void;
  onSelectedChanged: (instanceId: string | null) => void;
  onStickerDraggedOff?: (id: string, allIds: string[]) => void;
  onDragNearEdge?: (outsideCanvas: boolean) => void;
  onPointerUpCommit?: () => void;
  onMoveActiveChanged?: (active: boolean) => void;
  onDoubleTap?: (ids: string[]) => void;
  /** Returns the current selection's bounding box (canvas-local) + rotation, or null. */
  getSelectionBounds?: () => { box: { x: number; y: number; w: number; h: number }; rotation: number } | null;
};


// ── GestureHandler ───────────────────────────────────────────────────────────
export class StickerGestureHandler {
  private pointers: ActivePointer[] = [];


  // Freehand lasso state
  private lassoActive = false;
  private lassoPath: { x: number; y: number }[] = [];

  // Move state
  private moveActive = false;
  private moveOffsetX = 0;
  private moveOffsetY = 0;
  private moveBaselines: MoveBaseline[] = [];
  private didMove = false;

  // Pinch state
  private pinchBaseDistance = 0;
  private pinchBaseAngle = 0;
  private pinchBaselines: GroupBaseline[] = [];

  // Tap detection
  private tapStartX = 0;
  private tapStartY = 0;
  private tapMoved = false;

  // Double-tap detection
  private lastTapTime = 0;
  private lastTapX = 0;
  private lastTapY = 0;

  // Snapshot
  private stickers: StickerPlacement[] = [];
  private selectedInstanceId: string | null = null;
  private lassoSelection: Set<string> = new Set();

  constructor(
    private readonly getCanvasRect: () => DOMRect,
    private readonly hitTest: (clientX: number, clientY: number) => string | null,
    private readonly callbacks: GestureCallbacks,
  ) {
  }

  public syncState(
    stickers: StickerPlacement[],
    selectedInstanceId: string | null,
    lassoSelection: Set<string>,
  ): void {
    this.stickers = stickers;
    this.selectedInstanceId = selectedInstanceId;
    this.lassoSelection = lassoSelection;
  }


  // ── Pointer events ────────────────────────────────────────────────────────

  public onPointerDown(id: number, clientX: number, clientY: number): void {
    this.pointers.push({id, x: clientX, y: clientY});

    // Second finger → upgrade to pinch
    if (this.pointers.length === 2) {
      this.tapMoved = true;
      this.lassoActive = false;
      this.lassoPath = [];
      this.callbacks.onLassoPathChanged(null);
      this.moveActive = false;
      const ids = this.currentSelectionIds();
      if (ids.length > 0) this.initPinch(ids);
      return;
    }

    // First finger
    this.tapStartX = clientX;
    this.tapStartY = clientY;
    this.tapMoved = false;
    this.didMove = false;

    const rect = this.getCanvasRect();
    const localX = clientX - rect.left;
    const localY = clientY - rect.top;
    const hitId = this.hitTest(clientX, clientY);

    if (this.hasSelection()) {
      // If the tap lands inside the selection's bounding box, drag it —
      // regardless of whether a sticker hitbox was actually hit.
      // This makes small stickers and groups much easier to move.
      const selBounds = this.callbacks.getSelectionBounds?.();
      const inBounds = selBounds
        ? pointInRotatedRect(localX, localY, selBounds.box, selBounds.rotation, 8)
        : false;

      if (inBounds) {
        // Inside the overlay → move current selection
        this.startMove(localX, localY);
      } else if (!hitId) {
        // Outside bounds, no hitbox hit → deselect + start lasso
        this.selectedInstanceId = null;
        this.lassoSelection = new Set();
        this.callbacks.onSelectedChanged(null);
        this.callbacks.onLassoSelectionChanged(new Set());
        this.lassoActive = true;
        this.lassoPath = [{x: localX, y: localY}];
        this.callbacks.onLassoPathChanged(this.lassoPath);
      } else if (!this.isSelected(hitId)) {
        // Hit a different sticker outside the selection → switch to it
        this.selectAndMove(hitId, localX, localY);
      } else {
        // Hit an already-selected sticker → move
        this.startMove(localX, localY);
      }
    } else if (hitId) {
      this.selectAndMove(hitId, localX, localY);
    } else {
      // Empty area → freehand lasso
      this.lassoActive = true;
      this.lassoPath = [{x: localX, y: localY}];
      this.callbacks.onLassoPathChanged(this.lassoPath);
    }
  }

  public onPointerMove(id: number, clientX: number, clientY: number): void {
    const idx = this.pointers.findIndex(p => p.id === id);
    if (idx < 0) return;
    this.pointers[idx] = {id, x: clientX, y: clientY};

    if (!this.tapMoved && Math.hypot(clientX - this.tapStartX, clientY - this.tapStartY) > 6)
      this.tapMoved = true;

    const rect = this.getCanvasRect();
    const localX = clientX - rect.left;
    const localY = clientY - rect.top;

    if (this.pointers.length === 2 && this.pinchBaselines.length > 0) {
      this.applyPinch();
      this.didMove = true;
      return;
    }

    if (this.moveActive && this.pointers.length === 1) {
      const dx = localX - this.moveOffsetX;
      const dy = localY - this.moveOffsetY;
      const updated = this.stickers.map(p => {
        const b = this.moveBaselines.find(b => b.instanceId === p.instanceId);
        return b ? {...p, x: b.baseX + dx, y: b.baseY + dy} : p;
      });
      this.callbacks.onPlacementsChanged(updated);
      this.didMove = true;
      if (this.callbacks.onDragNearEdge && this.hasSelection()) {
        this.callbacks.onDragNearEdge(
          this.isPointerOrCentroidNotOnCanvas(clientX, clientY, rect, updated),
        );
      }
      return;
    }

    if (this.lassoActive && this.pointers.length === 1) {
      const last = this.lassoPath[this.lassoPath.length - 1];
      if (!last || distance(localX, localY, last.x, last.y) > 2) {
        this.lassoPath.push({x: localX, y: localY});
        this.callbacks.onLassoPathChanged([...this.lassoPath]);
      }
    }
  }

  public onPointerUp(id: number, clientX: number, clientY: number): void {
    this.pointers = this.pointers.filter(p => p.id !== id);

    if (this.pointers.length === 0) {

      if (this.moveActive && this.tapMoved && this.callbacks.onStickerDraggedOff) {
        const rect = this.getCanvasRect();
        // Compute final placements with the current move offsets
        // (this.stickers may be stale — syncState hasn't run yet)
        const localX = clientX - rect.left;
        const localY = clientY - rect.top;
        const dx = localX - this.moveOffsetX;
        const dy = localY - this.moveOffsetY;
        const finalPlacements = this.stickers.map(p => {
          const b = this.moveBaselines.find(b => b.instanceId === p.instanceId);
          return b ? {...p, x: b.baseX + dx, y: b.baseY + dy} : p;
        });
        const outside = this.isPointerOrCentroidNotOnCanvas(clientX, clientY, rect, finalPlacements);
        if (outside && this.hasSelection()) {
          const ids = this.currentSelectionIds();
          this.selectedInstanceId = null;
          this.lassoSelection = new Set();
          this.moveActive = false;
          this.moveBaselines = [];
          this.callbacks.onMoveActiveChanged?.(false);
          this.callbacks.onSelectedChanged(null);
          this.callbacks.onLassoSelectionChanged(new Set());
          this.callbacks.onDragNearEdge?.(false);
          this.callbacks.onStickerDraggedOff(ids[0], ids);
          return;
        }
      }

      if (this.didMove) {
        this.callbacks.onPointerUpCommit?.();
      }
      this.finaliseLasso();
      this.moveActive = false;
      this.moveBaselines = [];
      this.pinchBaselines = [];
      this.didMove = false;
      this.callbacks.onMoveActiveChanged?.(false);
      this.callbacks.onDragNearEdge?.(false);

      // Double-tap detection
      if (!this.tapMoved && this.hasSelection()) {
        const now = Date.now();
        const dist = distance(clientX, clientY, this.lastTapX, this.lastTapY);
        if (now - this.lastTapTime < 350 && dist < 30) {
          this.callbacks.onDoubleTap?.(this.currentSelectionIds());
          this.lastTapTime = 0; // reset so triple-tap doesn't fire again
        } else {
          this.lastTapTime = now;
          this.lastTapX = clientX;
          this.lastTapY = clientY;
        }
      }
    }

    // Re-anchor when going 2 → 1 finger
    if (this.pointers.length === 1 && this.moveActive) {
      const remaining = this.pointers[0];
      const rect = this.getCanvasRect();
      this.moveOffsetX = remaining.x - rect.left;
      this.moveOffsetY = remaining.y - rect.top;
      this.moveBaselines = this.selectedStickers()
        .map(p => ({instanceId: p.instanceId, baseX: p.x, baseY: p.y}));
      this.pinchBaselines = [];
    }
  }

  // ── Private helpers ───────────────────────────────────────────────────────

  private hasSelection(): boolean {
    return !!this.selectedInstanceId || this.lassoSelection.size > 0;
  }

  /**
   * Returns true if the pointer OR the centroid of the selected stickers
   * is outside the canvas bounds. This allows stickers to be deleted when
   * they're dragged to the edge even if the pointer is still barely inside.
   */
  private isPointerOrCentroidNotOnCanvas(clientX: number, clientY: number, rect: DOMRect, placements?: StickerPlacement[]): boolean {
    if (isPointerOutsideRect(clientX, clientY, rect)) return true;

    const source = placements ?? this.stickers;
    const sel = source.filter(p => this.isSelected(p.instanceId));
    if (sel.length === 0) return false;
    const c = centroid(sel);
    return isPositionOutsideCanvas(c.x, c.y, rect);
  }

  private isSelected(id: string): boolean {
    return this.selectedInstanceId === id || this.lassoSelection.has(id);
  }

  private currentSelectionIds(): string[] {
    if (this.lassoSelection.size > 0) return [...this.lassoSelection];
    return this.selectedInstanceId ? [this.selectedInstanceId] : [];
  }

  private selectedStickers(): StickerPlacement[] {
    return this.stickers.filter(p => this.isSelected(p.instanceId));
  }

  // Returns all instanceIds for the same group if hit sticker belongs to one,
  // otherwise just [hitId].
  private resolveHit(hitId: string): string[] {
    const hit = this.stickers.find(p => p.instanceId === hitId);
    if (hit?.groupId) {
      return this.stickers
        .filter(p => p.groupId === hit.groupId)
        .map(p => p.instanceId);
    }
    return [hitId];
  }

  private selectAndMove(hitId: string, localX: number, localY: number): void {
    const ids = this.resolveHit(hitId);
    if (ids.length > 1) {
      const groupSet = new Set(ids);
      this.lassoSelection = groupSet;
      this.selectedInstanceId = null;
      // Emit lasso first; do NOT call onSelectedChanged(null) afterwards —
      // that would trigger clearSelection() in the canvas and wipe the lasso set.
      this.callbacks.onLassoSelectionChanged(groupSet);
    } else {
      this.selectedInstanceId = hitId;
      this.lassoSelection = new Set();
      this.callbacks.onSelectedChanged(hitId);
      this.callbacks.onLassoSelectionChanged(new Set());
    }
    this.startMove(localX, localY);
  }

  private startMove(localX: number, localY: number): void {
    this.moveActive = true;
    this.moveOffsetX = localX;
    this.moveOffsetY = localY;
    this.moveBaselines = this.selectedStickers()
      .map(p => ({instanceId: p.instanceId, baseX: p.x, baseY: p.y}));
  }

  private finaliseLasso(): void {
    if (!this.lassoActive) return;
    this.lassoActive = false;
    this.callbacks.onLassoPathChanged(null);

    const path = this.lassoPath;
    this.lassoPath = [];

    if (path.length < 2) return;

    // Build closed polygon — if only 2 points, expand to a rect
    let poly: { x: number; y: number }[];
    if (path.length === 2) {
      const [a, b] = path;
      poly = [
        {x: a.x, y: a.y}, {x: b.x, y: a.y},
        {x: b.x, y: b.y}, {x: a.x, y: b.y},
        {x: a.x, y: a.y},
      ];
    } else {
      poly = [...path, path[0]];
    }

    const captured = this.stickers.filter(p => pointInPoly(p.x, p.y, poly));

    if (captured.length > 1) {
      // First clear single selection, then set the lasso group
      this.callbacks.onSelectedChanged(null);
      this.callbacks.onLassoSelectionChanged(new Set(captured.map(p => p.instanceId)));
    } else if (captured.length === 1) {
      this.callbacks.onLassoSelectionChanged(new Set());
      this.callbacks.onSelectedChanged(captured[0].instanceId);
    }
  }

  private initPinch(ids: string[]): void {
    if (this.pointers.length < 2) return;
    const [a, b] = this.pointers;
    const pp = {ax: a.x, ay: a.y, bx: b.x, by: b.y};
    const rect = this.getCanvasRect();
    this.pinchBaseDistance = pinchDistance(pp);
    this.pinchBaseAngle = pinchAngle(pp);
    const mid = pinchMidpoint(pp, rect);
    this.pinchBaselines = ids
      .map(iid => this.stickers.find(p => p.instanceId === iid))
      .filter((p): p is StickerPlacement => !!p)
      .map(p => ({
        instanceId: p.instanceId,
        baseX: p.x,
        baseY: p.y,
        baseScale: p.scale,
        baseRotation: p.rotation,
        relCx: p.x - mid.x,
        relCy: p.y - mid.y,
      }));
  }

  private applyPinch(): void {
    if (this.pointers.length < 2 || !this.pinchBaselines.length) return;
    const [a, b] = this.pointers;
    const pp = {ax: a.x, ay: a.y, bx: b.x, by: b.y};
    const mid = pinchMidpoint(pp, this.getCanvasRect());
    const rawFactor = pinchDistance(pp) / this.pinchBaseDistance;
    const factor = clampGroupScaleFactor(rawFactor, this.pinchBaselines.map(bl => bl.baseScale));
    this.callbacks.onPlacementsChanged(
      this.stickers.map(p => {
        const base = this.pinchBaselines.find(b => b.instanceId === p.instanceId);
        if (!base) return p;
        const result = applyPinchToBaseline(base, this.pinchBaseAngle, factor, pp, mid);
        return {...p, ...result};
      }),
    );
  }
}

import {Component, input, output, computed, signal, OnDestroy, AfterViewInit, ElementRef} from '@angular/core';
import {CommonModule} from '@angular/common';
import gsap from 'gsap';
import {SvgComponent} from '../../svg/svg.component';
import {BoundingBox} from '../sticker-types';
import {degToRad, rotatePt, radToDeg, angleBetween} from '../geometry-helpers';

export interface HandleDragEvent {
  handle: 'scale' | 'rotate' | 'n' | 's' | 'e' | 'w';
  dx: number;
  dy: number;
  done: boolean;
}

export type OverlayMode = 'idle' | 'moving' | 'rotating' | 'scaling' | 'menu';

export const DARK_PURPLE = '#d6dc55'
export const LIGHT_PURPLE = '#374151'
export const LIGHT_PURPLE_SEMI = 'rgba(55,65,81,0.45)'



@Component({
  selector: 'app-sticker-selection-overlay',
  standalone: true,
  imports: [CommonModule, SvgComponent],
  templateUrl: './sticker-selection-overlay.component.html',
  host: {style: 'position:absolute;inset:0;pointer-events:none;'},
})
export class StickerSelectionOverlayComponent implements AfterViewInit, OnDestroy {
  readonly padding = input<number>(0)
  readonly box = input<BoundingBox | null>(null);
  readonly rotation = input<number>(0);
  readonly stretchModeVisible = input<boolean>(false);
  /** Whether the parent is currently handling a move/drag gesture. */
  readonly isDragging = input<boolean>(false);
  /** Whether the context menu is currently open. */
  readonly isMenuOpen = input<boolean>(false);

  readonly handleDrag = output<HandleDragEvent>();
  readonly menuToggle = output<void>();

  constructor(private readonly hostRef: ElementRef<HTMLElement>) {
  }

  ngAfterViewInit(): void {
    // Fade in all handle circles + SVG on creation.
    // Only animate opacity — no scale/transform tweens on positioned elements,
    // because Angular updates their left/top every frame during moves.
    const el = this.hostRef.nativeElement;
    const targets = el.querySelectorAll<HTMLElement>('div[style*="pointer-events:auto"], svg');
    if (targets.length) {
      gsap.fromTo(targets,
        {opacity: 0},
        {
          opacity: 1, duration: 0.18, ease: 'power2.out', stagger: 0.02,
          clearProps: 'opacity'
        },
      );
    }
  }

  // ── Internal drag tracking ────────────────────────────────────────────────
  private internalMode = signal<'idle' | 'rotating' | 'scaling'>('idle');
  private lastX = 0;
  private lastY = 0;
  private lastAngle = 0;
  private cleanupPtr: (() => void) | null = null;

  // ── Derived active mode (single source of truth for the template) ─────────
  readonly activeMode = computed<OverlayMode>(() => {
    if (this.internalMode() !== 'idle') return this.internalMode();
    if (this.isDragging()) return 'moving';
    if (this.isMenuOpen()) return 'menu';
    return 'idle';
  });

  protected readonly Math = Math;
  protected readonly rotatePt = rotatePt;
  protected readonly svgRect = (tl: { x: number; y: number }, tr: { x: number; y: number },
                                br: { x: number; y: number }, bl: { x: number; y: number }) =>
    `${tl.x},${tl.y} ${tr.x},${tr.y} ${br.x},${br.y} ${bl.x},${bl.y}`;

  readonly sides = computed(() => {
    const b = this.box();
    if (!b) return [];
    const pad = this.padding();
    const cx = b.x + b.w / 2, cy = b.y + b.h / 2;
    const rad = degToRad(this.rotation());
    return [
      {id: 'n' as const, lx: b.x + b.w / 2, ly: b.y - pad, cursor: 'n-resize'},
      {id: 's' as const, lx: b.x + b.w / 2, ly: b.y + b.h + pad, cursor: 's-resize'},
      {id: 'e' as const, lx: b.x + b.w + pad, ly: b.y + b.h / 2, cursor: 'e-resize'},
      {id: 'w' as const, lx: b.x - pad, ly: b.y + b.h / 2, cursor: 'w-resize'},
    ].map(r => {
      const p = rotatePt(r.lx, r.ly, cx, cy, rad);
      return {...r, x: p.x, y: p.y};
    });
  });

  onHandleDown(ev: PointerEvent, handle: HandleDragEvent['handle']): void {
    ev.preventDefault();
    ev.stopPropagation();
    this.internalMode.set(handle === 'rotate' ? 'rotating' : 'scaling');
    this.lastX = ev.clientX;
    this.lastY = ev.clientY;

    const canvasEl = (ev.target as HTMLElement).closest('[data-canvas-overlay]')?.parentElement ?? null;
    const canvasRect = canvasEl?.getBoundingClientRect() ?? null;

    if (handle === 'rotate' && canvasRect) {
      const b = this.box()!;
      this.lastAngle = angleBetween(canvasRect.left + b.x + b.w / 2, canvasRect.top + b.y + b.h / 2, ev.clientX, ev.clientY);
    }

    const onMove = (e: PointerEvent) => {
      if (this.internalMode() === 'idle') return;
      if (this.internalMode() === 'rotating' && canvasRect) {
        const b = this.box()!;
        const angle = angleBetween(canvasRect.left + b.x + b.w / 2, canvasRect.top + b.y + b.h / 2, e.clientX, e.clientY);
        let delta = radToDeg(angle - this.lastAngle);
        if (delta > 180) delta -= 360;
        if (delta < -180) delta += 360;
        this.lastAngle = angle;
        if (Math.abs(delta) > 0.05) {
          this.handleDrag.emit({handle: 'rotate', dx: delta, dy: 0, done: false});
        }
        return;
      }
      const screenDx = e.clientX - this.lastX;
      const screenDy = e.clientY - this.lastY;
      this.lastX = e.clientX;
      this.lastY = e.clientY;
      if (Math.abs(screenDx) < 0.5 && Math.abs(screenDy) < 0.5) {
        return;
      }
      const local = rotatePt(screenDx, screenDy, 0, 0, -degToRad(this.rotation()));
      this.handleDrag.emit({handle, dx: local.x, dy: local.y, done: false});
    };
    const onUp = () => {
      if (this.internalMode() !== 'idle') this.handleDrag.emit({handle, dx: 0, dy: 0, done: true});
      this.internalMode.set('idle');
      cleanup();
    };
    const cleanup = () => {
      document.removeEventListener('pointermove', onMove);
      document.removeEventListener('pointerup', onUp);
      this.cleanupPtr = null;
    };
    document.addEventListener('pointermove', onMove);
    document.addEventListener('pointerup', onUp);
    this.cleanupPtr = cleanup;
  }

  ngOnDestroy(): void {
    this.cleanupPtr?.();
  }

  protected readonly DARK_PURPLE = DARK_PURPLE;
  protected readonly LIGHT_PURPLE = LIGHT_PURPLE;
  protected readonly LIGHT_PURPLE_SEMI = LIGHT_PURPLE_SEMI;
}

import type {StickerPlacement} from "@birthday/shared";
import {
    pointInPoly,
    pointInRotatedRect,
    isPointerOutsideRect,
    isPositionOutsideCanvas,
    distance,
    centroid,
    pinchDistance,
    pinchAngle,
    pinchMidpoint,
    applyPinchToBaseline,
    clampGroupScaleFactor,
} from '../geometry-helpers';

// ── Types ────────────────────────────────────────────────────────────────────

export interface ActivePointer {
  id: number;
  x: number;
  y: number;
}

export interface GroupBaseline {
  instanceId: string;
  baseX: number;
  baseY: number;
  baseScale: number;
  baseRotation: number;
  relCx: number;
  relCy: number;
}

export interface MoveBaseline {
  instanceId: string;
  baseX: number;
  baseY: number;
}

export type GestureCallbacks = {
  onPlacementsChanged: (placements: StickerPlacement[]) => void;
  onLassoPathChanged: (path: { x: number; y: number }[] | null) => void;
  onLassoSelectionChanged: (ids: Set<string>) => void;
  onSelectedChanged: (instanceId: string | null) => void;
  onStickerDraggedOff?: (id: string, allIds: string[]) => void;
  onDragNearEdge?: (outsideCanvas: boolean) => void;
  onPointerUpCommit?: () => void;
  onMoveActiveChanged?: (active: boolean) => void;
  onDoubleTap?: (ids: string[]) => void;
  /** Returns the current selection's bounding box (canvas-local) + rotation, or null. */
  getSelectionBounds?: () => { box: { x: number; y: number; w: number; h: number }; rotation: number } | null;
};


// ── GestureHandler ───────────────────────────────────────────────────────────
export class StickerGestureHandler {
  private pointers: ActivePointer[] = [];


  // Freehand lasso state
  private lassoActive = false;
  private lassoPath: { x: number; y: number }[] = [];

  // Move state
  private moveActive = false;
  private moveOffsetX = 0;
  private moveOffsetY = 0;
  private moveBaselines: MoveBaseline[] = [];
  private didMove = false;

  // Pinch state
  private pinchBaseDistance = 0;
  private pinchBaseAngle = 0;
  private pinchBaselines: GroupBaseline[] = [];

  // Tap detection
  private tapStartX = 0;
  private tapStartY = 0;
  private tapMoved = false;

  // Double-tap detection
  private lastTapTime = 0;
  private lastTapX = 0;
  private lastTapY = 0;

  // Snapshot
  private stickers: StickerPlacement[] = [];
  private selectedInstanceId: string | null = null;
  private lassoSelection: Set<string> = new Set();

  constructor(
    private readonly getCanvasRect: () => DOMRect,
    private readonly hitTest: (clientX: number, clientY: number) => string | null,
    private readonly callbacks: GestureCallbacks,
  ) {
  }

  public syncState(
    stickers: StickerPlacement[],
    selectedInstanceId: string | null,
    lassoSelection: Set<string>,
  ): void {
    this.stickers = stickers;
    this.selectedInstanceId = selectedInstanceId;
    this.lassoSelection = lassoSelection;
  }


  // ── Pointer events ────────────────────────────────────────────────────────

  public onPointerDown(id: number, clientX: number, clientY: number): void {
    this.pointers.push({id, x: clientX, y: clientY});

    // Second finger → upgrade to pinch
    if (this.pointers.length === 2) {
      this.tapMoved = true;
      this.lassoActive = false;
      this.lassoPath = [];
      this.callbacks.onLassoPathChanged(null);
      this.moveActive = false;
      const ids = this.currentSelectionIds();
      if (ids.length > 0) this.initPinch(ids);
      return;
    }

    // First finger
    this.tapStartX = clientX;
    this.tapStartY = clientY;
    this.tapMoved = false;
    this.didMove = false;

    const rect = this.getCanvasRect();
    const localX = clientX - rect.left;
    const localY = clientY - rect.top;
    const hitId = this.hitTest(clientX, clientY);

    if (this.hasSelection()) {
      // If the tap lands inside the selection's bounding box, drag it —
      // regardless of whether a sticker hitbox was actually hit.
      // This makes small stickers and groups much easier to move.
      const selBounds = this.callbacks.getSelectionBounds?.();
      const inBounds = selBounds
        ? pointInRotatedRect(localX, localY, selBounds.box, selBounds.rotation, 8)
        : false;

      if (inBounds) {
        // Inside the overlay → move current selection
        this.startMove(localX, localY);
      } else if (!hitId) {
        // Outside bounds, no hitbox hit → deselect + start lasso
        this.selectedInstanceId = null;
        this.lassoSelection = new Set();
        this.callbacks.onSelectedChanged(null);
        this.callbacks.onLassoSelectionChanged(new Set());
        this.lassoActive = true;
        this.lassoPath = [{x: localX, y: localY}];
        this.callbacks.onLassoPathChanged(this.lassoPath);
      } else if (!this.isSelected(hitId)) {
        // Hit a different sticker outside the selection → switch to it
        this.selectAndMove(hitId, localX, localY);
      } else {
        // Hit an already-selected sticker → move
        this.startMove(localX, localY);
      }
    } else if (hitId) {
      this.selectAndMove(hitId, localX, localY);
    } else {
      // Empty area → freehand lasso
      this.lassoActive = true;
      this.lassoPath = [{x: localX, y: localY}];
      this.callbacks.onLassoPathChanged(this.lassoPath);
    }
  }

  public onPointerMove(id: number, clientX: number, clientY: number): void {
    const idx = this.pointers.findIndex(p => p.id === id);
    if (idx < 0) return;
    this.pointers[idx] = {id, x: clientX, y: clientY};

    if (!this.tapMoved && Math.hypot(clientX - this.tapStartX, clientY - this.tapStartY) > 6)
      this.tapMoved = true;

    const rect = this.getCanvasRect();
    const localX = clientX - rect.left;
    const localY = clientY - rect.top;

    if (this.pointers.length === 2 && this.pinchBaselines.length > 0) {
      this.applyPinch();
      this.didMove = true;
      return;
    }

    if (this.moveActive && this.pointers.length === 1) {
      const dx = localX - this.moveOffsetX;
      const dy = localY - this.moveOffsetY;
      const updated = this.stickers.map(p => {
        const b = this.moveBaselines.find(b => b.instanceId === p.instanceId);
        return b ? {...p, x: b.baseX + dx, y: b.baseY + dy} : p;
      });
      this.callbacks.onPlacementsChanged(updated);
      this.didMove = true;
      if (this.callbacks.onDragNearEdge && this.hasSelection()) {
        this.callbacks.onDragNearEdge(
          this.isPointerOrCentroidNotOnCanvas(clientX, clientY, rect, updated),
        );
      }
      return;
    }

    if (this.lassoActive && this.pointers.length === 1) {
      const last = this.lassoPath[this.lassoPath.length - 1];
      if (!last || distance(localX, localY, last.x, last.y) > 2) {
        this.lassoPath.push({x: localX, y: localY});
        this.callbacks.onLassoPathChanged([...this.lassoPath]);
      }
    }
  }

  public onPointerUp(id: number, clientX: number, clientY: number): void {
    this.pointers = this.pointers.filter(p => p.id !== id);

    if (this.pointers.length === 0) {

      if (this.moveActive && this.tapMoved && this.callbacks.onStickerDraggedOff) {
        const rect = this.getCanvasRect();
        // Compute final placements with the current move offsets
        // (this.stickers may be stale — syncState hasn't run yet)
        const localX = clientX - rect.left;
        const localY = clientY - rect.top;
        const dx = localX - this.moveOffsetX;
        const dy = localY - this.moveOffsetY;
        const finalPlacements = this.stickers.map(p => {
          const b = this.moveBaselines.find(b => b.instanceId === p.instanceId);
          return b ? {...p, x: b.baseX + dx, y: b.baseY + dy} : p;
        });
        const outside = this.isPointerOrCentroidNotOnCanvas(clientX, clientY, rect, finalPlacements);
        if (outside && this.hasSelection()) {
          const ids = this.currentSelectionIds();
          this.selectedInstanceId = null;
          this.lassoSelection = new Set();
          this.moveActive = false;
          this.moveBaselines = [];
          this.callbacks.onMoveActiveChanged?.(false);
          this.callbacks.onSelectedChanged(null);
          this.callbacks.onLassoSelectionChanged(new Set());
          this.callbacks.onDragNearEdge?.(false);
          this.callbacks.onStickerDraggedOff(ids[0], ids);
          return;
        }
      }

      if (this.didMove) {
        this.callbacks.onPointerUpCommit?.();
      }
      this.finaliseLasso();
      this.moveActive = false;
      this.moveBaselines = [];
      this.pinchBaselines = [];
      this.didMove = false;
      this.callbacks.onMoveActiveChanged?.(false);
      this.callbacks.onDragNearEdge?.(false);

      // Double-tap detection
      if (!this.tapMoved && this.hasSelection()) {
        const now = Date.now();
        const dist = distance(clientX, clientY, this.lastTapX, this.lastTapY);
        if (now - this.lastTapTime < 350 && dist < 30) {
          this.callbacks.onDoubleTap?.(this.currentSelectionIds());
          this.lastTapTime = 0; // reset so triple-tap doesn't fire again
        } else {
          this.lastTapTime = now;
          this.lastTapX = clientX;
          this.lastTapY = clientY;
        }
      }
    }

    // Re-anchor when going 2 → 1 finger
    if (this.pointers.length === 1 && this.moveActive) {
      const remaining = this.pointers[0];
      const rect = this.getCanvasRect();
      this.moveOffsetX = remaining.x - rect.left;
      this.moveOffsetY = remaining.y - rect.top;
      this.moveBaselines = this.selectedStickers()
        .map(p => ({instanceId: p.instanceId, baseX: p.x, baseY: p.y}));
      this.pinchBaselines = [];
    }
  }

  // ── Private helpers ───────────────────────────────────────────────────────

  private hasSelection(): boolean {
    return !!this.selectedInstanceId || this.lassoSelection.size > 0;
  }

  /**
   * Returns true if the pointer OR the centroid of the selected stickers
   * is outside the canvas bounds. This allows stickers to be deleted when
   * they're dragged to the edge even if the pointer is still barely inside.
   */
  private isPointerOrCentroidNotOnCanvas(clientX: number, clientY: number, rect: DOMRect, placements?: StickerPlacement[]): boolean {
    if (isPointerOutsideRect(clientX, clientY, rect)) return true;

    const source = placements ?? this.stickers;
    const sel = source.filter(p => this.isSelected(p.instanceId));
    if (sel.length === 0) return false;
    const c = centroid(sel);
    return isPositionOutsideCanvas(c.x, c.y, rect);
  }

  private isSelected(id: string): boolean {
    return this.selectedInstanceId === id || this.lassoSelection.has(id);
  }

  private currentSelectionIds(): string[] {
    if (this.lassoSelection.size > 0) return [...this.lassoSelection];
    return this.selectedInstanceId ? [this.selectedInstanceId] : [];
  }

  private selectedStickers(): StickerPlacement[] {
    return this.stickers.filter(p => this.isSelected(p.instanceId));
  }

  // Returns all instanceIds for the same group if hit sticker belongs to one,
  // otherwise just [hitId].
  private resolveHit(hitId: string): string[] {
    const hit = this.stickers.find(p => p.instanceId === hitId);
    if (hit?.groupId) {
      return this.stickers
        .filter(p => p.groupId === hit.groupId)
        .map(p => p.instanceId);
    }
    return [hitId];
  }

  private selectAndMove(hitId: string, localX: number, localY: number): void {
    const ids = this.resolveHit(hitId);
    if (ids.length > 1) {
      const groupSet = new Set(ids);
      this.lassoSelection = groupSet;
      this.selectedInstanceId = null;
      // Emit lasso first; do NOT call onSelectedChanged(null) afterwards —
      // that would trigger clearSelection() in the canvas and wipe the lasso set.
      this.callbacks.onLassoSelectionChanged(groupSet);
    } else {
      this.selectedInstanceId = hitId;
      this.lassoSelection = new Set();
      this.callbacks.onSelectedChanged(hitId);
      this.callbacks.onLassoSelectionChanged(new Set());
    }
    this.startMove(localX, localY);
  }

  private startMove(localX: number, localY: number): void {
    this.moveActive = true;
    this.moveOffsetX = localX;
    this.moveOffsetY = localY;
    this.moveBaselines = this.selectedStickers()
      .map(p => ({instanceId: p.instanceId, baseX: p.x, baseY: p.y}));
  }

  private finaliseLasso(): void {
    if (!this.lassoActive) return;
    this.lassoActive = false;
    this.callbacks.onLassoPathChanged(null);

    const path = this.lassoPath;
    this.lassoPath = [];

    if (path.length < 2) return;

    // Build closed polygon — if only 2 points, expand to a rect
    let poly: { x: number; y: number }[];
    if (path.length === 2) {
      const [a, b] = path;
      poly = [
        {x: a.x, y: a.y}, {x: b.x, y: a.y},
        {x: b.x, y: b.y}, {x: a.x, y: b.y},
        {x: a.x, y: a.y},
      ];
    } else {
      poly = [...path, path[0]];
    }

    const captured = this.stickers.filter(p => pointInPoly(p.x, p.y, poly));

    if (captured.length > 1) {
      // First clear single selection, then set the lasso group
      this.callbacks.onSelectedChanged(null);
      this.callbacks.onLassoSelectionChanged(new Set(captured.map(p => p.instanceId)));
    } else if (captured.length === 1) {
      this.callbacks.onLassoSelectionChanged(new Set());
      this.callbacks.onSelectedChanged(captured[0].instanceId);
    }
  }

  private initPinch(ids: string[]): void {
    if (this.pointers.length < 2) return;
    const [a, b] = this.pointers;
    const pp = {ax: a.x, ay: a.y, bx: b.x, by: b.y};
    const rect = this.getCanvasRect();
    this.pinchBaseDistance = pinchDistance(pp);
    this.pinchBaseAngle = pinchAngle(pp);
    const mid = pinchMidpoint(pp, rect);
    this.pinchBaselines = ids
      .map(iid => this.stickers.find(p => p.instanceId === iid))
      .filter((p): p is StickerPlacement => !!p)
      .map(p => ({
        instanceId: p.instanceId,
        baseX: p.x,
        baseY: p.y,
        baseScale: p.scale,
        baseRotation: p.rotation,
        relCx: p.x - mid.x,
        relCy: p.y - mid.y,
      }));
  }

  private applyPinch(): void {
    if (this.pointers.length < 2 || !this.pinchBaselines.length) return;
    const [a, b] = this.pointers;
    const pp = {ax: a.x, ay: a.y, bx: b.x, by: b.y};
    const mid = pinchMidpoint(pp, this.getCanvasRect());
    const rawFactor = pinchDistance(pp) / this.pinchBaseDistance;
    const factor = clampGroupScaleFactor(rawFactor, this.pinchBaselines.map(bl => bl.baseScale));
    this.callbacks.onPlacementsChanged(
      this.stickers.map(p => {
        const base = this.pinchBaselines.find(b => b.instanceId === p.instanceId);
        if (!base) return p;
        const result = applyPinchToBaseline(base, this.pinchBaseAngle, factor, pp, mid);
        return {...p, ...result};
      }),
    );
  }
}

export function clamp(v: number, min: number, max: number): number {
    return Math.max(min, Math.min(max, v));
}

/** Convert degrees to radians. */
export function degToRad(deg: number): number {
    return deg * Math.PI / 180;
}

/** Convert radians to degrees. */
export function radToDeg(rad: number): number {
    return rad * (180 / Math.PI);
}

// ── Point / vector math ───────────────────────────────────────────────────────

/** Euclidean distance between two points. */
export function distance(ax: number, ay: number, bx: number, by: number): number {
    return Math.hypot(bx - ax, by - ay);
}

/** Angle (radians) from point A to point B. */
export function angleBetween(ax: number, ay: number, bx: number, by: number): number {
    return Math.atan2(by - ay, bx - ax);
}

/** Midpoint between two points. */
export function midpoint(ax: number, ay: number, bx: number, by: number): { x: number; y: number } {
    return {x: (ax + bx) / 2, y: (ay + by) / 2};
}

/** Centroid (average position) of a list of {x, y} points. */
export function centroid(points: { x: number; y: number }[]): { x: number; y: number } {
    if (!points.length) return {x: 0, y: 0};
    const sx = points.reduce((s, p) => s + p.x, 0);
    const sy = points.reduce((s, p) => s + p.y, 0);
    return {x: sx / points.length, y: sy / points.length};
}

// ── Rotation ──────────────────────────────────────────────────────────────────

/**
 * Rotate a point around a center by `rad` radians.
 */
export function rotatePt(
    x: number, y: number,
    cx: number, cy: number,
    rad: number,
): { x: number; y: number } {
    const cos = Math.cos(rad), sin = Math.sin(rad);
    const dx = x - cx, dy = y - cy;
    return {x: cx + dx * cos - dy * sin, y: cy + dx * sin + dy * cos};
}

// ── Hit testing ───────────────────────────────────────────────────────────────

/**
 * Ray-casting point-in-polygon test.
 * Polygon vertices are in any consistent coordinate space.
 */
export function pointInPoly(
    px: number, py: number,
    poly: { x: number; y: number }[],
): boolean {
    let inside = false;
    for (let i = 0, j = poly.length - 1; i < poly.length; j = i++) {
        const xi = poly[i].x, yi = poly[i].y;
        const xj = poly[j].x, yj = poly[j].y;
        if ((yi > py) !== (yj > py) && px < ((xj - xi) * (py - yi)) / (yj - yi) + xi)
            inside = !inside;
    }
    return inside;
}

/**
 * Returns true if the canvas-local point (px, py) lies inside a rotated rectangle.
 * The rectangle is axis-aligned before rotation; rotation is around the box center.
 * `padding` expands the box on all sides.
 */
export function pointInRotatedRect(
    px: number, py: number,
    box: { x: number; y: number; w: number; h: number },
    rotationDeg: number,
    padding = 0,
): boolean {
    const cx = box.x + box.w / 2;
    const cy = box.y + box.h / 2;
    const rad = -degToRad(rotationDeg);
    const cos = Math.cos(rad), sin = Math.sin(rad);
    const dx = px - cx, dy = py - cy;
    // Rotate the point into box-local frame
    const lx = dx * cos - dy * sin;
    const ly = dx * sin + dy * cos;
    return Math.abs(lx) <= box.w / 2 + padding && Math.abs(ly) <= box.h / 2 + padding;
}

// ── Canvas / pointer helpers ──────────────────────────────────────────────────

/**
 * Returns true if the client-space pointer position is outside the given DOMRect.
 */
export function isPointerOutsideRect(clientX: number, clientY: number, rect: DOMRect): boolean {
    return clientX < rect.left || clientX > rect.right ||
           clientY < rect.top  || clientY > rect.bottom;
}

/**
 * Returns true if the given canvas-local position (x, y) is outside the canvas.
 */
export function isPositionOutsideCanvas(x: number, y: number, rect: DOMRect): boolean {
    return x < 0 || x > rect.width || y < 0 || y > rect.height;
}

// ── Pinch / two-finger gesture math ──────────────────────────────────────────

export interface PinchPoints {
    ax: number; ay: number;
    bx: number; by: number;
}

/** Distance between two touch points. */
export function pinchDistance(p: PinchPoints): number {
    return distance(p.ax, p.ay, p.bx, p.by) || 1;
}

/** Angle (radians) between two touch points. */
export function pinchAngle(p: PinchPoints): number {
    return angleBetween(p.ax, p.ay, p.bx, p.by);
}

/** Canvas-local midpoint of two touch points. */
export function pinchMidpoint(p: PinchPoints, rect: DOMRect): { x: number; y: number } {
    const mid = midpoint(p.ax, p.ay, p.bx, p.by);
    return {x: mid.x - rect.left, y: mid.y - rect.top};
}

export interface PinchBaseline {
    relCx: number;
    relCy: number;
    baseScale: number;
    baseRotation: number;
}

/**
 * Given a single sticker's pinch baseline (position relative to the gesture centre,
 * plus its original scale/rotation), compute the new x, y, scale and rotation after
 * the gesture has moved to `currentPoints`.
 *
 * `mid` is the canvas-local gesture midpoint (from `pinchMidpoint`).
 *
 * The `scaleFactor` should already be clamped at the group level by the caller
 * so that no sticker in the group exceeds [MIN_SCALE, MAX_SCALE].
 */
export function applyPinchToBaseline(
    baseline: PinchBaseline,
    baseAngleRad: number,
    scaleFactor: number,
    currentPoints: PinchPoints,
    mid: { x: number; y: number },
): { x: number; y: number; scale: number; rotation: number } {
    const newAngle = pinchAngle(currentPoints);
    const angleRad    = newAngle - baseAngleRad;
    const angleDelta  = radToDeg(angleRad);

    const cos = Math.cos(angleRad), sin = Math.sin(angleRad);
    return {
        x:        mid.x + (baseline.relCx * cos - baseline.relCy * sin) * scaleFactor,
        y:        mid.y + (baseline.relCx * sin + baseline.relCy * cos) * scaleFactor,
        scale:    baseline.baseScale * scaleFactor,
        rotation: baseline.baseRotation + angleDelta,
    };
}

/** Scale limits for individual stickers. */
export const MIN_SCALE = 0.2;
export const MAX_SCALE = 4;

/**
 * Clamp a scaleFactor so that every sticker's resulting scale stays within
 * [MIN_SCALE, MAX_SCALE]. This keeps groups consistent — all members scale
 * by the same factor, so relative positions are preserved.
 */
export function clampGroupScaleFactor(
    factor: number,
    baseScales: number[],
): number {
    if (!baseScales.length) return factor;
    let lo = 0;   // highest lower bound (factor must be >= this)
    let hi = Infinity; // lowest upper bound (factor must be <= this)
    for (const bs of baseScales) {
        if (bs <= 0) continue;
        lo = Math.max(lo, MIN_SCALE / bs);
        hi = Math.min(hi, MAX_SCALE / bs);
    }
    // If lo > hi the group can't satisfy all constraints — pick the closer bound
    if (lo > hi) return factor < (lo + hi) / 2 ? lo : hi;
    return clamp(factor, lo, hi);
}

// ── Vector / bounding-box helpers ─────────────────────────────────────────────

/**
 * Rotate a 2-D vector (dx, dy) around the origin by `rad` radians.
 * Equivalent to `rotatePt(dx, dy, 0, 0, rad)` but returns a plain tuple.
 */
export function rotateVec(dx: number, dy: number, rad: number): { x: number; y: number } {
    const cos = Math.cos(rad), sin = Math.sin(rad);
    return {x: dx * cos - dy * sin, y: dx * sin + dy * cos};
}

/**
 * Given a list of axis-aligned half-extents (hw, hh), centers (cx, cy) and
 * per-item rotation angles `itemRads`, projects all four corners of each
 * item into a common frame that is rotated by `-frameRad` around `origin`,
 * then returns the axis-aligned bounding box in that frame.
 *
 * Used by `computeSelectionInfo` for both group and lasso selections.
 */
export function rotatedBoundingBox(
    items: { cx: number; cy: number; hw: number; hh: number; itemRad: number }[],
    origin: { x: number; y: number },
    frameRad: number,
): { minX: number; minY: number; maxX: number; maxY: number } {
    const cos = Math.cos(-frameRad), sin = Math.sin(-frameRad);
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (const {cx, cy, hw, hh, itemRad} of items) {
        const pCos = Math.cos(itemRad), pSin = Math.sin(itemRad);
        for (const [ex, ey] of [[-hw, -hh], [hw, -hh], [hw, hh], [-hw, hh]] as [number, number][]) {
            // World position of this corner
            const wx = cx + ex * pCos - ey * pSin;
            const wy = cy + ex * pSin + ey * pCos;
            // Rotate into frame
            const dx = wx - origin.x, dy = wy - origin.y;
            const lx = origin.x + dx * cos - dy * sin;
            const ly = origin.y + dx * sin + dy * cos;
            if (lx < minX) minX = lx; if (lx > maxX) maxX = lx;
            if (ly < minY) minY = ly; if (ly > maxY) maxY = ly;
        }
    }
    return {minX, minY, maxX, maxY};
}

export function clamp(v: number, min: number, max: number): number {
    return Math.max(min, Math.min(max, v));
}

/** Convert degrees to radians. */
export function degToRad(deg: number): number {
    return deg * Math.PI / 180;
}

/** Convert radians to degrees. */
export function radToDeg(rad: number): number {
    return rad * (180 / Math.PI);
}

// ── Point / vector math ───────────────────────────────────────────────────────

/** Euclidean distance between two points. */
export function distance(ax: number, ay: number, bx: number, by: number): number {
    return Math.hypot(bx - ax, by - ay);
}

/** Angle (radians) from point A to point B. */
export function angleBetween(ax: number, ay: number, bx: number, by: number): number {
    return Math.atan2(by - ay, bx - ax);
}

/** Midpoint between two points. */
export function midpoint(ax: number, ay: number, bx: number, by: number): { x: number; y: number } {
    return {x: (ax + bx) / 2, y: (ay + by) / 2};
}

/** Centroid (average position) of a list of {x, y} points. */
export function centroid(points: { x: number; y: number }[]): { x: number; y: number } {
