    return inside;
}

/**
 * Returns true if the canvas-local point (px, py) lies inside a rotated rectangle.
 * The rectangle is axis-aligned before rotation; rotation is around the box center.
 * `padding` expands the box on all sides.
 */
export function pointInRotatedRect(
    px: number, py: number,
    box: { x: number; y: number; w: number; h: number },
    rotationDeg: number,
    padding = 0,
): boolean {
    const cx = box.x + box.w / 2;
    const cy = box.y + box.h / 2;
    const rad = -degToRad(rotationDeg);
    const cos = Math.cos(rad), sin = Math.sin(rad);
    const dx = px - cx, dy = py - cy;
    // Rotate the point into box-local frame
    const lx = dx * cos - dy * sin;
    const ly = dx * sin + dy * cos;
    return Math.abs(lx) <= box.w / 2 + padding && Math.abs(ly) <= box.h / 2 + padding;
}

// ── Canvas / pointer helpers ──────────────────────────────────────────────────

/**
 * Returns true if the client-space pointer position is outside the given DOMRect.
 */
export function isPointerOutsideRect(clientX: number, clientY: number, rect: DOMRect): boolean {
    return clientX < rect.left || clientX > rect.right ||
           clientY < rect.top  || clientY > rect.bottom;
}

/**
 * Returns true if the given canvas-local position (x, y) is outside the canvas.
 */
export function isPositionOutsideCanvas(x: number, y: number, rect: DOMRect): boolean {
    return x < 0 || x > rect.width || y < 0 || y > rect.height;
}

// ── Pinch / two-finger gesture math ──────────────────────────────────────────

export interface PinchPoints {
    ax: number; ay: number;
    bx: number; by: number;
}

/** Distance between two touch points. */
export function pinchDistance(p: PinchPoints): number {
    return distance(p.ax, p.ay, p.bx, p.by) || 1;
}

/** Angle (radians) between two touch points. */
export function pinchAngle(p: PinchPoints): number {
    return angleBetween(p.ax, p.ay, p.bx, p.by);
}

/** Canvas-local midpoint of two touch points. */
export function pinchMidpoint(p: PinchPoints, rect: DOMRect): { x: number; y: number } {
    const mid = midpoint(p.ax, p.ay, p.bx, p.by);
    return {x: mid.x - rect.left, y: mid.y - rect.top};
}

export interface PinchBaseline {
    relCx: number;
    relCy: number;
    baseScale: number;
    baseRotation: number;
}

/**
 * Given a single sticker's pinch baseline (position relative to the gesture centre,
 * plus its original scale/rotation), compute the new x, y, scale and rotation after
 * the gesture has moved to `currentPoints`.
 *
 * `mid` is the canvas-local gesture midpoint (from `pinchMidpoint`).
 *
 * The `scaleFactor` should already be clamped at the group level by the caller
 * so that no sticker in the group exceeds [MIN_SCALE, MAX_SCALE].
 */
export function applyPinchToBaseline(
    baseline: PinchBaseline,
    baseAngleRad: number,
    scaleFactor: number,
    currentPoints: PinchPoints,
    mid: { x: number; y: number },
): { x: number; y: number; scale: number; rotation: number } {
    const newAngle = pinchAngle(currentPoints);
    const angleRad    = newAngle - baseAngleRad;
    const angleDelta  = radToDeg(angleRad);

    const cos = Math.cos(angleRad), sin = Math.sin(angleRad);
    return {
        x:        mid.x + (baseline.relCx * cos - baseline.relCy * sin) * scaleFactor,
        y:        mid.y + (baseline.relCx * sin + baseline.relCy * cos) * scaleFactor,
        scale:    baseline.baseScale * scaleFactor,
        rotation: baseline.baseRotation + angleDelta,
    };
}

/** Scale limits for individual stickers. */
export const MIN_SCALE = 0.2;
export const MAX_SCALE = 4;

/**
 * Clamp a scaleFactor so that every sticker's resulting scale stays within
 * [MIN_SCALE, MAX_SCALE]. This keeps groups consistent — all members scale
 * by the same factor, so relative positions are preserved.
 */
export function clampGroupScaleFactor(
    factor: number,
    baseScales: number[],
): number {
    if (!baseScales.length) return factor;
    let lo = 0;   // highest lower bound (factor must be >= this)
    let hi = Infinity; // lowest upper bound (factor must be <= this)
    for (const bs of baseScales) {
        if (bs <= 0) continue;
        lo = Math.max(lo, MIN_SCALE / bs);
        hi = Math.min(hi, MAX_SCALE / bs);
    }
    // If lo > hi the group can't satisfy all constraints — pick the closer bound
    if (lo > hi) return factor < (lo + hi) / 2 ? lo : hi;
    return clamp(factor, lo, hi);
}

// ── Vector / bounding-box helpers ─────────────────────────────────────────────

/**
 * Rotate a 2-D vector (dx, dy) around the origin by `rad` radians.
 * Equivalent to `rotatePt(dx, dy, 0, 0, rad)` but returns a plain tuple.
 */
export function rotateVec(dx: number, dy: number, rad: number): { x: number; y: number } {
    const cos = Math.cos(rad), sin = Math.sin(rad);
    return {x: dx * cos - dy * sin, y: dx * sin + dy * cos};
}

/**
 * Given a list of axis-aligned half-extents (hw, hh), centers (cx, cy) and
 * per-item rotation angles `itemRads`, projects all four corners of each
 * item into a common frame that is rotated by `-frameRad` around `origin`,
 * then returns the axis-aligned bounding box in that frame.
 *
 * Used by `computeSelectionInfo` for both group and lasso selections.
 */
export function rotatedBoundingBox(
    items: { cx: number; cy: number; hw: number; hh: number; itemRad: number }[],
    origin: { x: number; y: number },
    frameRad: number,
): { minX: number; minY: number; maxX: number; maxY: number } {
    const cos = Math.cos(-frameRad), sin = Math.sin(-frameRad);
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (const {cx, cy, hw, hh, itemRad} of items) {
        const pCos = Math.cos(itemRad), pSin = Math.sin(itemRad);
        for (const [ex, ey] of [[-hw, -hh], [hw, -hh], [hw, hh], [-hw, hh]] as [number, number][]) {
            // World position of this corner
            const wx = cx + ex * pCos - ey * pSin;
            const wy = cy + ex * pSin + ey * pCos;
            // Rotate into frame
            const dx = wx - origin.x, dy = wy - origin.y;
            const lx = origin.x + dx * cos - dy * sin;
            const ly = origin.y + dx * sin + dy * cos;
            if (lx < minX) minX = lx; if (lx > maxX) maxX = lx;
            if (ly < minY) minY = ly; if (ly > maxY) maxY = ly;
        }
    }
    return {minX, minY, maxX, maxY};
}

import {resolveToImgUrl} from '../../../shared/sticker-editor/sprite-url.util';

export interface Point {
    x: number;
    y: number;
}

// ── Public API ──────────────────────────────────────────────

/**
 * Load the image, render it to a canvas, extract the alpha mask,
 * trace the contour and simplify it.
 *
 * @param imageUrl  URL of the PNG (can be relative)
 * @param tolerance Douglas–Peucker tolerance (0–1 normalised). Higher = fewer points.
 * @param alphaThreshold  Pixel is "solid" if alpha >= this value (0–255).
 * @returns Array of normalised {x, y} points forming the polygon.
 */
export async function autoDetectHitbox(
    imageUrl: string,
    tolerance = 0.02,
    alphaThreshold = 20,
): Promise<Point[]> {
    const img = await loadImage(imageUrl);
    const {width, height, alphaData} = getAlphaData(img, alphaThreshold);
    const contour = traceContour(alphaData, width, height);
    if (contour.length < 3) return [];

    // Normalise to 0–1
    const normalised = contour.map(p => ({
        x: p.x / width,
        y: p.y / height,
    }));

    // Simplify
    const simplified = douglasPeucker(normalised, tolerance);

    // Round to 2 decimal places
    const result = simplified.map(p => ({
        x: Math.round(p.x * 100) / 100,
        y: Math.round(p.y * 100) / 100,
    }));

    // Remove duplicate closing point (tracing a closed contour may leave first === last)
    if (result.length > 1) {
        const first = result[0];
        const last = result[result.length - 1];
        if (first.x === last.x && first.y === last.y) {
            result.pop();
        }
    }

    return result;
}

// ── Image loading ───────────────────────────────────────────

async function loadImage(imageUrl: string): Promise<HTMLImageElement> {
    const { url } = await resolveToImgUrl(imageUrl, 512);
    return new Promise((resolve, reject) => {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.onload = () => {
            URL.revokeObjectURL(url);
            resolve(img);
        };
        img.onerror = () => {
            URL.revokeObjectURL(url);
            reject(new Error(`Failed to load image: ${imageUrl}`));
        };
        img.src = url;
    });
}

function getAlphaData(
    img: HTMLImageElement,
    alphaThreshold: number,
): { width: number; height: number; alphaData: Uint8Array } {
    const canvas = document.createElement("canvas");
    const w = img.naturalWidth;
    const h = img.naturalHeight;
    canvas.width = w;
    canvas.height = h;
    const ctx = canvas.getContext("2d")!;
    ctx.drawImage(img, 0, 0);
    const imageData = ctx.getImageData(0, 0, w, h);

    // Binary alpha mask: 1 = solid, 0 = transparent
    const alpha = new Uint8Array(w * h);
    for (let i = 0; i < w * h; i++) {
        alpha[i] = imageData.data[i * 4 + 3] >= alphaThreshold ? 1 : 0;
    }
    return {width: w, height: h, alphaData: alpha};
}

// ── Contour tracing (simple boundary walk) ──────────────────

function traceContour(
    alpha: Uint8Array,
    w: number,
    h: number,
): Point[] {
    // Find a starting solid pixel on the boundary (scan from top-left)
    let startX = -1, startY = -1;
    outer:
    for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (alpha[y * w + x] === 1) {
                // Check if it's a boundary pixel (has at least one transparent neighbor)
                if (isBoundary(alpha, w, h, x, y)) {
                    startX = x;
                    startY = y;
                    break outer;
                }
            }
        }
    }
    if (startX < 0) return [];

    // Walk the boundary using Moore neighborhood tracing
    const contour: Point[] = [];
    const visited = new Set<string>();
    const directions = [
        {dx: 1, dy: 0}, {dx: 1, dy: 1}, {dx: 0, dy: 1}, {dx: -1, dy: 1},
        {dx: -1, dy: 0}, {dx: -1, dy: -1}, {dx: 0, dy: -1}, {dx: 1, dy: -1},
    ];

    let cx = startX, cy = startY;
    let dir = 0; // start direction
    const maxSteps = w * h * 2; // safety limit
    let steps = 0;

    do {
        const key = `${cx},${cy}`;
        if (!visited.has(key)) {
            contour.push({x: cx, y: cy});
            visited.add(key);
        }

        // Find next boundary pixel
        let found = false;
        const startDir = (dir + 5) % 8; // start searching from dir-3 (backtrack)
        for (let i = 0; i < 8; i++) {
            const d = (startDir + i) % 8;
            const nx = cx + directions[d].dx;
            const ny = cy + directions[d].dy;
            if (nx >= 0 && nx < w && ny >= 0 && ny < h &&
                alpha[ny * w + nx] === 1 && isBoundary(alpha, w, h, nx, ny)) {
                cx = nx;
                cy = ny;
                dir = d;
                found = true;
                break;
            }
        }
        if (!found) break;
        steps++;
    } while ((cx !== startX || cy !== startY) && steps < maxSteps);

    return contour;
}

function isBoundary(alpha: Uint8Array, w: number, h: number, x: number, y: number): boolean {
    if (alpha[y * w + x] !== 1) return false;
    // Edge of image counts as boundary
    if (x === 0 || y === 0 || x === w - 1 || y === h - 1) return true;
    // Check 4-connected neighbors
    return (
        alpha[y * w + (x - 1)] === 0 ||
        alpha[y * w + (x + 1)] === 0 ||
        alpha[(y - 1) * w + x] === 0 ||
        alpha[(y + 1) * w + x] === 0
    );
}

// ── Douglas–Peucker line simplification ─────────────────────

function douglasPeucker(points: Point[], epsilon: number): Point[] {
    if (points.length <= 2) return points;

    let maxDist = 0;
    let maxIdx = 0;
    const first = points[0];
    const last = points[points.length - 1];

    for (let i = 1; i < points.length - 1; i++) {
        const d = perpendicularDistance(points[i], first, last);
        if (d > maxDist) {
            maxDist = d;
            maxIdx = i;
        }
    }

    if (maxDist > epsilon) {
        const left = douglasPeucker(points.slice(0, maxIdx + 1), epsilon);
        const right = douglasPeucker(points.slice(maxIdx), epsilon);
        return [...left.slice(0, -1), ...right];
    }

    return [first, last];
}

function perpendicularDistance(point: Point, lineStart: Point, lineEnd: Point): number {
    const dx = lineEnd.x - lineStart.x;
    const dy = lineEnd.y - lineStart.y;
    const lenSq = dx * dx + dy * dy;

    if (lenSq === 0) {
        return Math.hypot(point.x - lineStart.x, point.y - lineStart.y);
    }

    const t = Math.max(0, Math.min(1,
        ((point.x - lineStart.x) * dx + (point.y - lineStart.y) * dy) / lenSq));
    const projX = lineStart.x + t * dx;
    const projY = lineStart.y + t * dy;

    return Math.hypot(point.x - projX, point.y - projY);
}

import { Injectable } from "@angular/core";
import type { ActivatedRoute } from "@angular/router";

const RECONNECT_STORAGE_KEY = "birthday_reconnect";
const DEVICE_NAME_KEY = "birthday_device_player_name";

export interface ReconnectPayload {
  /** Server-assigned player UUID — used to reclaim the same player slot on rejoin. */
  playerId: string;
  /** Server-assigned session UUID — used to verify the player belongs to this session. */
  sessionId: string;
}

@Injectable({ providedIn: "root" })
export class ReconnectService {
  public load(): ReconnectPayload | null {
    try {
      const raw = localStorage.getItem(RECONNECT_STORAGE_KEY);
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      if (parsed?.playerId && parsed?.sessionId) {
        return { playerId: parsed.playerId, sessionId: parsed.sessionId };
      }
    } catch { /* ignore */ }
    return null;
  }

  public save(payload: ReconnectPayload): void {
    localStorage.setItem(RECONNECT_STORAGE_KEY, JSON.stringify(payload));
  }

  public update(partial: Partial<ReconnectPayload>): void {
    const existing = this.load();
    const updated: ReconnectPayload = {
      playerId: partial.playerId ?? existing?.playerId ?? "",
      sessionId: partial.sessionId ?? existing?.sessionId ?? "",
    };
    if (updated.playerId && updated.sessionId) {
      this.save(updated);
    }
  }

  /** Remove all stored reconnect data (e.g. when the session is deleted). */
  public clear(): void {
    localStorage.removeItem(RECONNECT_STORAGE_KEY);
  }

  /** Resolve the session code from the route query param only — no localStorage fallback. */
  public resolveSessionCode(route: ActivatedRoute): string | null {
    const routeCode = route.snapshot.queryParamMap.get("session");
    return routeCode?.trim().toUpperCase() ?? null;
  }

  // ── Device-level identity (survives session changes) ──────────

  public saveDeviceName(name: string): void {
    localStorage.setItem(DEVICE_NAME_KEY, name);
  }

  public loadDeviceName(): string | null {
    return localStorage.getItem(DEVICE_NAME_KEY) || null;
  }
}

import { Injectable } from "@angular/core";
import { HttpClient } from "@angular/common/http";
import type { SessionInfo } from "@birthday/shared";
import { firstValueFrom } from "rxjs";

export interface ResolvedSessionInfo {
  sessionId: string;
  sessionCode: string;
  createdAt: number;
  expiresAt: number;
}

export interface SessionSummary {
  sessionId: string;
  sessionCode: string;
  playerCount: number;
  createdAt: number;
  expiresAt: number;
}

@Injectable({ providedIn: "root" })
export class ApiService {
  public constructor(private readonly httpClient: HttpClient) {}

  public listSessions(): Promise<SessionSummary[]> {
    return firstValueFrom(this.httpClient.get<SessionSummary[]>("/api/sessions"));
  }

  public createSession(): Promise<SessionInfo> {
    return firstValueFrom(this.httpClient.post<SessionInfo>("/api/sessions", { }));
  }

  public resolveSessionByCode(sessionCode: string): Promise<ResolvedSessionInfo> {
    return firstValueFrom(
      this.httpClient.get<ResolvedSessionInfo>(`/api/sessions/by-code/${encodeURIComponent(sessionCode)}`),
    );
  }

  public deleteSession(sessionId: string): Promise<void> {
    return firstValueFrom(this.httpClient.delete<void>(`/api/sessions/${encodeURIComponent(sessionId)}`));
  }

  public uploadCollageImage(sessionId: string, playerId: string, collageId: string, imageDataUrl: string): Promise<{ok: boolean; publicUrl: string}> {
    return firstValueFrom(
      this.httpClient.post<{ok: boolean; publicUrl: string}>(
        `/api/sessions/${encodeURIComponent(sessionId)}/collage-image`,
        {playerId, collageId, imageDataUrl},
      ),
    );
  }

  public getSessionAssets(sessionId: string): Promise<Array<{type: "avatar" | "collage"; filename: string; publicUrl: string}>> {
    return firstValueFrom(
      this.httpClient.get<Array<{type: "avatar" | "collage"; filename: string; publicUrl: string}>>(
        `/api/sessions/${encodeURIComponent(sessionId)}/assets`,
      ),
    );
  }
}

