import { Injectable } from "@angular/core";
import { HttpClient } from "@angular/common/http";
import type { SessionInfo } from "@birthday/shared";
import { firstValueFrom } from "rxjs";

export interface ResolvedSessionInfo {
  sessionId: string;
  sessionCode: string;
  createdAt: number;
  expiresAt: number;
}

export interface SessionSummary {
  sessionId: string;
  sessionCode: string;
  playerCount: number;
  createdAt: number;
  expiresAt: number;
}

@Injectable({ providedIn: "root" })
export class ApiService {
  public constructor(private readonly httpClient: HttpClient) {}

  public listSessions(): Promise<SessionSummary[]> {
    return firstValueFrom(this.httpClient.get<SessionSummary[]>("/api/sessions"));
  }

  public createSession(): Promise<SessionInfo> {
    return firstValueFrom(this.httpClient.post<SessionInfo>("/api/sessions", { }));
  }

  public resolveSessionByCode(sessionCode: string): Promise<ResolvedSessionInfo> {
    return firstValueFrom(
      this.httpClient.get<ResolvedSessionInfo>(`/api/sessions/by-code/${encodeURIComponent(sessionCode)}`),
    );
  }

  public deleteSession(sessionId: string): Promise<void> {
    return firstValueFrom(this.httpClient.delete<void>(`/api/sessions/${encodeURIComponent(sessionId)}`));
  }

  public uploadCollageImage(sessionId: string, playerId: string, collageId: string, imageDataUrl: string): Promise<{ok: boolean; publicUrl: string}> {
    return firstValueFrom(
      this.httpClient.post<{ok: boolean; publicUrl: string}>(
        `/api/sessions/${encodeURIComponent(sessionId)}/collage-image`,
        {playerId, collageId, imageDataUrl},
      ),
    );
  }

  public getSessionAssets(sessionId: string): Promise<Array<{type: "avatar" | "collage"; filename: string; publicUrl: string}>> {
    return firstValueFrom(
      this.httpClient.get<Array<{type: "avatar" | "collage"; filename: string; publicUrl: string}>>(
        `/api/sessions/${encodeURIComponent(sessionId)}/assets`,
      ),
    );
  }
}

import {Injectable} from "@angular/core";
import type {Point} from "./auto-hitbox.util";
import {PolygonEditService} from "./polygon-edit.service";

/**
 * Handles mouse and keyboard interaction for the hitbox editor canvas.
 * Translates raw DOM events into polygon-edit operations.
 */
@Injectable()
export class EditorInteractionHandler {
    private draggingVertex = -1;

    constructor(private readonly polygonEdit: PolygonEditService) {}

    // ── Mouse events ────────────────────────────────────────

    /**
     * Call on mousedown inside the editor wrapper.
     * Handles vertex selection, edge insertion, and new-point creation.
     */
    public onMouseDown(event: MouseEvent): void {
        const {x, y} = this.getNormCoords(event);
        const pts = this.polygonEdit.polygon();
        const {imgW, imgH} = this.getImagePixelSize(event);

        // 1. Vertex hit?
        for (let i = 0; i < pts.length; i++) {
            if (Math.hypot((pts[i].x - x) * imgW, (pts[i].y - y) * imgH) < 14) {
                this.polygonEdit.select(i);
                this.draggingVertex = i;
                event.preventDefault();
                return;
            }
        }

        // 2. Edge midpoint / line hit? → insert point
        if (pts.length >= 2) {
            for (let i = 0; i < pts.length; i++) {
                const j = (i + 1) % pts.length;
                const mx = (pts[i].x + pts[j].x) / 2;
                const my = (pts[i].y + pts[j].y) / 2;
                if (Math.hypot((mx - x) * imgW, (my - y) * imgH) < 10) {
                    this.insertAndDrag(j, mx, my, event);
                    return;
                }
                const dist = ptSegDistPx(x, y, pts[i], pts[j], imgW, imgH);
                if (dist < 10) {
                    const proj = projectOntoSeg(x, y, pts[i], pts[j]);
                    this.insertAndDrag(j, proj.x, proj.y, event);
                    return;
                }
            }
        }

        // 3. Empty space → add point
        this.draggingVertex = this.polygonEdit.addVertex(x, y);
        event.preventDefault();
    }

    /** Call on mousemove inside the editor wrapper. */
    public onMouseMove(event: MouseEvent): void {
        if (this.draggingVertex < 0) return;
        const {x, y} = this.getNormCoords(event);
        this.polygonEdit.moveVertex(this.draggingVertex, x, y);
    }

    /** Call on mouseup / mouseleave inside the editor wrapper. */
    public onMouseUp(): void {
        this.draggingVertex = -1;
    }

    // ── Keyboard events ─────────────────────────────────────

    /**
     * Call on keydown. Returns true if the event was handled
     * (caller should preventDefault).
     */
    public onKeyDown(event: KeyboardEvent): boolean {
        if (event.key === "Backspace" || event.key === "Delete") {
            return this.polygonEdit.removeSelected();
        }
        return false;
    }

    // ── Helpers ──────────────────────────────────────────────

    private insertAndDrag(atIndex: number, x: number, y: number, event: MouseEvent): void {
        this.draggingVertex = this.polygonEdit.insertVertex(atIndex, x, y);
        event.preventDefault();
    }

    /**
     * Compute the image pixel size from the wrapper element.
     * The wrapper is (1 + 2*overflowFraction) × imageSize, so:
     *   imageSize = wrapperSize / (1 + 2*overflowFraction)
     */
    private getImagePixelSize(event: MouseEvent): {imgW: number; imgH: number} {
        const target = event.currentTarget as HTMLElement;
        return {
            imgW: target.clientWidth,
            imgH: target.clientHeight,
        };
    }

    /**
     * Convert a mouse event to normalised image coordinates.
     * (0,0) = top-left of image, (1,1) = bottom-right.
     * Values can be slightly outside [0,1] in the overflow zone.
     */
    private getNormCoords(event: MouseEvent): {x: number; y: number} {
        const target = event.currentTarget as HTMLElement;
        const rect = target.getBoundingClientRect();
        const imgW = rect.width;
        const imgH = rect.height;
        return {
            x: Math.max(0, Math.min(1, (event.clientX - rect.left) / imgW)),
            y: Math.max(0, Math.min(1, (event.clientY - rect.top) / imgH)),
        };
    }
}

// ── Geometry helpers (pure functions) ────────────────────────

function ptSegDistPx(px: number, py: number, a: Point, b: Point, imgW: number, imgH: number): number {
    const ax = a.x * imgW, ay = a.y * imgH;
    const bx = b.x * imgW, by = b.y * imgH;
    const ppx = px * imgW, ppy = py * imgH;
    const dx = bx - ax, dy = by - ay;
    const lenSq = dx * dx + dy * dy;
    if (lenSq === 0) return Math.hypot(ppx - ax, ppy - ay);
    const t = Math.max(0, Math.min(1, ((ppx - ax) * dx + (ppy - ay) * dy) / lenSq));
    return Math.hypot(ppx - (ax + t * dx), ppy - (ay + t * dy));
}

function projectOntoSeg(px: number, py: number, a: Point, b: Point): Point {
    const dx = b.x - a.x, dy = b.y - a.y;
    const lenSq = dx * dx + dy * dy;
    if (lenSq === 0) return {x: a.x, y: a.y};
    const t = Math.max(0, Math.min(1, ((px - a.x) * dx + (py - a.y) * dy) / lenSq));
    return {x: a.x + t * dx, y: a.y + t * dy};
}

import { Injectable, signal } from "@angular/core";

export type PlayerUiMode = "LOBBY" | "STICKER_COLLAGE" | "IDLE";

@Injectable({ providedIn: "root" })
export class GameSessionStore {
  public readonly sessionId = signal<string | null>(null);
  public readonly playerId = signal<string | null>(null);
  public readonly clientId = signal<string | null>(null);
  public readonly playerName = signal<string>("");
  public readonly currentMode = signal<PlayerUiMode>("LOBBY");
  public readonly feedback = signal<{ text: string; type: "success" | "error" } | null>(null);

  public setSession(sessionId: string): void {
    this.sessionId.set(sessionId);
  }

  public setJoined(args: { sessionId: string; playerId: string; clientId: string }): void {
    this.sessionId.set(args.sessionId);
    this.playerId.set(args.playerId);
    this.clientId.set(args.clientId);
  }

  public clearTask(nextMode: PlayerUiMode = "IDLE"): void {
    this.currentMode.set(nextMode);
  }

  public showFeedback(text: string, type: "success" | "error"): void {
    this.feedback.set({ text, type });
    setTimeout(() => this.feedback.set(null), 2500);
  }
}

import {Injectable, signal, effect} from "@angular/core";
import {HttpClient} from "@angular/common/http";
import {firstValueFrom, Subject} from "rxjs";
import {debounceTime} from "rxjs/operators";
import type {StickerDefinition} from "@birthday/shared";
import type {Point} from "./auto-hitbox.util";
import {PolygonEditService} from "./polygon-edit.service";

/** Fallback catalog when backend is unavailable */
const FALLBACK_CATALOG: StickerDefinition[] = [];

/**
 * Handles loading the sticker catalog, persisting hitbox data,
 * and debounced auto-save.
 */
@Injectable()
export class HitboxPersistenceService {
    /** Full sticker catalog */
    public readonly catalog = signal<StickerDefinition[]>([]);

    /** Currently selected sticker */
    public readonly selectedSticker = signal<StickerDefinition | null>(null);

    /** UI feedback signals */
    public readonly saving = signal(false);
    public readonly saveStatus = signal<string>("");

    private readonly saveRequest$ = new Subject<void>();

    constructor(
        private readonly http: HttpClient,
        private readonly polygonEdit: PolygonEditService,
    ) {
        // Watch polygon for changes → debounced auto-save
        effect(() => {
            const pts = this.polygonEdit.polygon();
            if (pts.length >= 3) {
                this.saveRequest$.next();
            }
        });

        this.saveRequest$.pipe(debounceTime(800)).subscribe(() => {
            this.save();
        });
    }

    // ── Catalog ─────────────────────────────────────────────

    public async loadCatalog(): Promise<void> {
        try {
            const data = await firstValueFrom(
                this.http.get<StickerDefinition[]>("/api/sticker-catalog"),
            );
            if (data && data.length > 0) {
                this.catalog.set(data);
                return;
            }
        } catch { /* fall through to fallback */ }

        try {
            const hitboxData = await firstValueFrom(
                this.http.get<Record<string, Point[]>>("/api/hitbox-data"),
            ) ?? {};
            this.catalog.set(FALLBACK_CATALOG.map(s => {
                const poly = hitboxData[s.id];
                return (poly?.length ?? 0) >= 3 ? {...s, hitboxPolygon: poly} : s;
            }));
        } catch {
            this.catalog.set(FALLBACK_CATALOG);
        }
    }

    public hasSavedHitbox(sticker: StickerDefinition): boolean {
        return !!(sticker.hitboxPolygon && sticker.hitboxPolygon.length >= 3);
    }

    // ── Sticker selection ───────────────────────────────────

    public async selectSticker(sticker: StickerDefinition): Promise<void> {
        await this.flushSave();
        this.selectedSticker.set(sticker);
        this.polygonEdit.load(sticker.hitboxPolygon ? [...sticker.hitboxPolygon] : []);
    }

    // ── Persistence ─────────────────────────────────────────

    /** Immediately persist the current polygon to the backend. */
    public async save(): Promise<void> {
        const sticker = this.selectedSticker();
        if (!sticker) return;
        const pts = this.polygonEdit.polygon();
        if (pts.length < 3) return;

        this.saving.set(true);
        this.saveStatus.set("");
        try {
            await firstValueFrom(
                this.http.put(`/api/hitbox-data/${encodeURIComponent(sticker.id)}`, {polygon: pts}),
            );
            // Update catalog entry so the sidebar shows the green dot
            const current = this.catalog();
            const idx = current.findIndex(s => s.id === sticker.id);
            if (idx >= 0) {
                const updated = [...current];
                updated[idx] = {...updated[idx], hitboxPolygon: pts};
                this.catalog.set(updated);
            }
            this.saveStatus.set("✅");
        } catch {
            this.saveStatus.set("❌");
        } finally {
            this.saving.set(false);
            setTimeout(() => this.saveStatus.set(""), 2000);
        }
    }

    /** Force an immediate save if there's a valid polygon. */
    public async flushSave(): Promise<void> {
        if (this.selectedSticker() && this.polygonEdit.isValid()) {
            await this.save();
        }
    }

    /** Clean up (call from component ngOnDestroy). */
    public destroy(): void {
        this.flushSave();
        this.saveRequest$.complete();
    }
}

