import {Injectable} from "@angular/core";
import gsap from "gsap";

/**
 * Zentraler Service für Seiten-Übergänge.
 *
 * Komponenten registrieren ihren Host-Container beim Mounten.
 * Vor einer Navigation ruft der Aufrufer `leaveAndNavigate()` auf –
 * der Service animiert den registrierten Container aus und führt dann
 * die übergebene Aktion aus (z. B. `router.navigate()`).
 *
 * Verwendung in einer Komponente:
 *
 *   constructor(private transitions: PageTransitionService, private router: Router) {}
 *
 *   ngOnInit() {
 *     this.transitions.register(this.el.nativeElement);
 *   }
 *
 *   goSomewhere() {
 *     this.transitions.leaveAndNavigate(() => this.router.navigate(['/somewhere']));
 *   }
 */
@Injectable({providedIn: "root"})
export class PageTransitionService {
  private currentEl: HTMLElement | null = null;

  /** Registriert den Host-Container der aktuell aktiven Seite. */
  public register(el: HTMLElement): void {
    this.currentEl = el;
  }

  /** Deregistriert (beim Destroy der Komponente). */
  public unregister(el: HTMLElement): void {
    if (this.currentEl === el) this.currentEl = null;
  }

  /**
   * Fährt den aktuellen Screen mit einer kurzen Leave-Animation aus
   * und führt danach `action` aus.
   * Wenn kein Container registriert ist, wird `action` sofort ausgeführt.
   */
  public leaveAndNavigate(action: () => void, durationMs = 280): void {
    const el = this.currentEl;
    if (!el) {
      action();
      return;
    }

    gsap.to(el, {
      opacity: 0,
      y: -16,
      duration: durationMs / 1000,
      ease: "power2.in",
      overwrite: true,
      onComplete: action,
    });
  }
}

import {inject, Injectable, signal} from "@angular/core";
import {Router} from "@angular/router";
import type {ServerToClientMessage} from "@birthday/shared";
import {ReconnectService} from '../../../core/reconnect.service';
import {WebSocketService} from '../../../core/websocket.service';
import {WorldStore} from '../../../core/world.store';
import {GameSessionStore} from '../../../core/challenge.store';
import {StickerEventHandler} from './sticker-event-handler';

@Injectable()
export class PlayerMessageHandler {
  private readonly sessionStore = inject(GameSessionStore);
  private readonly worldStore = inject(WorldStore);
  private readonly wsService = inject(WebSocketService);
  private readonly reconnectService = inject(ReconnectService);
  private readonly router = inject(Router);
  private readonly stickerHandler = inject(StickerEventHandler);

  /** Expose the playerId so the component can read it after 'welcome'. */
  public readonly playerId = signal<string | null>(null);

  /** Session code, set by the component after route resolution. */
  public sessionCode = "";

  // ─── Main dispatch ──────────────────────────────────────────

  public handle(message: ServerToClientMessage): void {
    switch (message.type) {
      case "welcome":
        this.onWelcome(message);
        break;
      case "session-state":
        this.worldStore.setSessionState(message.state);
        this.syncPlayerModeFromState();
        break;
      case "game-event":
        this.stickerHandler.handleEvent(message.event);
        break;
      case "error":
        this.onError(message.message);
        break;
    }
  }

  // ─── Welcome ────────────────────────────────────────────────

  private onWelcome(message: Extract<ServerToClientMessage, { type: "welcome" }>): void {
    this.sessionStore.setJoined({
      sessionId: message.sessionId,
      playerId: message.playerId,
      clientId: message.clientId,
    });

    this.playerId.set(message.playerId);

    this.wsService.updatePendingJoin({
      type: "join",
      kind: "player",
      sessionId: message.sessionId,
      playerId: message.playerId,
    });

    this.reconnectService.save({
      playerId: message.playerId,
      sessionId: message.sessionId,
    });
  }

  // ─── State sync on reconnect ────────────────────────────────

  public syncPlayerModeFromState(): void {
    const playerId = this.sessionStore.playerId();
    const sessionState = this.worldStore.sessionState();
    if (!playerId || !sessionState) return;

    const player = sessionState.players[playerId];
    if (!player) {
      // Not yet in state — initial join in progress; next state push will include us.
      return;
    }

    if (player.name.trim().length > 0) {
      this.sessionStore.playerName.set(player.name);
    } else if (this.sessionStore.playerName().trim().length > 0) {
      // We have a device-level name the server doesn't know yet → send it
      this.wsService.send({type: "set-name", name: this.sessionStore.playerName()});
    }

    if (this.sessionStore.playerName().trim().length === 0 || !player.avatarUrl) {
      this.sessionStore.currentMode.set("LOBBY");
      return;
    }

    this.stickerHandler.syncMode();
  }

  // ─── Error handling ─────────────────────────────────────────

  private onError(message: string): void {
    this.sessionStore.showFeedback(message, "error");

    const isFatal = /nicht gefunden|abgelaufen|gelöscht|wurde gelöscht|closed|deleted/i.test(message);
    if (isFatal) {
      this.wsService.disconnect();
      this.reconnectService.clear();
      setTimeout(() => this.router.navigate(["/"]), 2000);
    }
  }
}

import {DestroyRef, effect, inject, Injectable, signal} from "@angular/core";

@Injectable()
export class PlayerTimerService {
  private readonly destroyRef = inject(DestroyRef);
  private timerInterval: ReturnType<typeof setInterval> | null = null;

  public readonly timeLeft = signal<string>("");

  constructor() {
    effect(() => {
      const endsAt = 0
      this.clearTimer();

      if (endsAt <= 0) {
        this.timeLeft.set("");
        return;
      }

      const updateCountdown = () => {
        const remaining = Math.max(0, endsAt - Date.now());
        const totalSec = Math.ceil(remaining / 1000);
        const min = Math.floor(totalSec / 60);
        const sec = totalSec % 60;
        this.timeLeft.set(`${min}:${String(sec).padStart(2, "0")}`);
      };

      updateCountdown();
      this.timerInterval = setInterval(updateCountdown, 500);
    });

    this.destroyRef.onDestroy(() => this.clearTimer());
  }

  private clearTimer(): void {
    if (this.timerInterval) {
      clearInterval(this.timerInterval);
      this.timerInterval = null;
    }
  }
}

import {Injectable, signal, computed} from "@angular/core";
import type {Point} from "./auto-hitbox.util";

/**
 * Manages the polygon state for the hitbox editor.
 * Pure state + operations — no I/O, no DOM, no side-effects.
 */
@Injectable()
export class PolygonEditService {
    /** Current polygon vertices (normalised 0–1) */
    public readonly polygon = signal<Point[]>([]);

    /** Index of the currently selected vertex (-1 = none) */
    public readonly selectedVertex = signal<number>(-1);

    /** True when polygon has >= 3 points (valid hitbox) */
    public readonly isValid = computed(() => this.polygon().length >= 3);

    // ── Bulk operations ─────────────────────────────────────

    /** Replace the entire polygon (e.g. after auto-detect or sticker switch) */
    public load(points: Point[]): void {
        this.polygon.set(points);
        this.selectedVertex.set(-1);
    }

    /** Clear all points */
    public clear(): void {
        this.polygon.set([]);
        this.selectedVertex.set(-1);
    }

    // ── Single-vertex operations ────────────────────────────

    /** Append a new point at the end and select it. Returns its index. */
    public addVertex(x: number, y: number): number {
        const pts = this.polygon();
        const idx = pts.length;
        this.polygon.set([...pts, round({x, y})]);
        this.selectedVertex.set(idx);
        return idx;
    }

    /** Insert a point at `atIndex`, shifting later points. Returns `atIndex`. */
    public insertVertex(atIndex: number, x: number, y: number): number {
        const pts = [...this.polygon()];
        pts.splice(atIndex, 0, round({x, y}));
        this.polygon.set(pts);
        this.selectedVertex.set(atIndex);
        return atIndex;
    }

    /** Remove the vertex at `index` and deselect. */
    public removeVertex(index: number): void {
        const pts = [...this.polygon()];
        pts.splice(index, 1);
        this.polygon.set(pts);
        this.selectedVertex.set(-1);
    }

    /** Move an existing vertex to new coordinates. */
    public moveVertex(index: number, x: number, y: number): void {
        const pts = [...this.polygon()];
        pts[index] = round({x, y});
        this.polygon.set(pts);
    }

    /** Select a vertex by index. */
    public select(index: number): void {
        this.selectedVertex.set(index);
    }


    /** Remove the currently selected vertex (if any). Returns true if one was removed. */
    public removeSelected(): boolean {
        const idx = this.selectedVertex();
        if (idx < 0 || idx >= this.polygon().length) return false;
        this.removeVertex(idx);
        return true;
    }
}

// ── Helpers ──────────────────────────────────────────────────

function round(p: Point): Point {
    return {
        x: Math.round(p.x * 100) / 100,
        y: Math.round(p.y * 100) / 100,
    };
}

import { Injectable } from "@angular/core";
import type { ActivatedRoute } from "@angular/router";

const RECONNECT_STORAGE_KEY = "birthday_reconnect";
const DEVICE_NAME_KEY = "birthday_device_player_name";

export interface ReconnectPayload {
  /** Server-assigned player UUID — used to reclaim the same player slot on rejoin. */
  playerId: string;
  /** Server-assigned session UUID — used to verify the player belongs to this session. */
  sessionId: string;
}

@Injectable({ providedIn: "root" })
export class ReconnectService {
  public load(): ReconnectPayload | null {
    try {
      const raw = localStorage.getItem(RECONNECT_STORAGE_KEY);
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      if (parsed?.playerId && parsed?.sessionId) {
        return { playerId: parsed.playerId, sessionId: parsed.sessionId };
      }
    } catch { /* ignore */ }
    return null;
  }

  public save(payload: ReconnectPayload): void {
    localStorage.setItem(RECONNECT_STORAGE_KEY, JSON.stringify(payload));
  }

  public update(partial: Partial<ReconnectPayload>): void {
    const existing = this.load();
    const updated: ReconnectPayload = {
      playerId: partial.playerId ?? existing?.playerId ?? "",
      sessionId: partial.sessionId ?? existing?.sessionId ?? "",
    };
    if (updated.playerId && updated.sessionId) {
      this.save(updated);
    }
  }

  /** Remove all stored reconnect data (e.g. when the session is deleted). */
  public clear(): void {
    localStorage.removeItem(RECONNECT_STORAGE_KEY);
  }

  /** Resolve the session code from the route query param only — no localStorage fallback. */
  public resolveSessionCode(route: ActivatedRoute): string | null {
    const routeCode = route.snapshot.queryParamMap.get("session");
    return routeCode?.trim().toUpperCase() ?? null;
  }

  // ── Device-level identity (survives session changes) ──────────

  public saveDeviceName(name: string): void {
    localStorage.setItem(DEVICE_NAME_KEY, name);
  }

  public loadDeviceName(): string | null {
    return localStorage.getItem(DEVICE_NAME_KEY) || null;
  }
}

import {inject, Injectable} from "@angular/core";
import type {StickerCollageServerEvent} from "@birthday/shared";
import {WorldStore} from '../../../core/world.store';
import {GameSessionStore} from '../../../core/challenge.store';

@Injectable()
export class StickerEventHandler {
    private readonly sessionStore = inject(GameSessionStore);
    private readonly worldStore = inject(WorldStore);

    public handleEvent(event: StickerCollageServerEvent): void {
        switch (event.type) {
            case "hand-dealt":
                if (event.targetPlayerId === this.sessionStore.playerId()) {
                    this.sessionStore.showFeedback("Deine Sticker-Hand ist da! 🎨", "success");
                }
                break;
            case "game-started":
                this.sessionStore.showFeedback("Das Spiel beginnt! 🎉", "success");
                break;
            case "round-started":
                this.sessionStore.showFeedback(`Runde ${event.roundIndex}: ${event.prompt}`, "success");
                break;
            case "collage-submitted": {
                const players = this.worldStore.players();
                const name = players[event.playerId]?.name ?? "Jemand";
                if (event.playerId !== this.sessionStore.playerId()) {
                    this.sessionStore.showFeedback(`${name} hat eingereicht! 🖼️`, "success");
                }
                break;
            }
            case "voting-started":
                this.sessionStore.showFeedback("Abstimmung gestartet! 🗳️", "success");
                break;
            case "vote-registered":
                break;
            case "results-ready":
                this.sessionStore.showFeedback("Ergebnisse sind da! 🏆", "success");
                break;
            case "pack-unlocked":
                this.sessionStore.showFeedback(`${event.packName} freigeschaltet! 🔓`, "success");
                break;
            case "prompt-chosen":
                this.sessionStore.showFeedback(`Nächster Prompt: ${event.prompt}`, "success");
                break;
            case "guaranteed-pack-chosen":
                this.sessionStore.showFeedback(`${event.packName} ist auf jeden Fall dabei! ⭐`, "success");
                break;
            case "round-ended":
                break;
            case "score-update":
                if (event.playerId === this.sessionStore.playerId()) {
                    this.sessionStore.showFeedback(`Du hast jetzt ${event.newScore} Punkte! ⭐`, "success");
                }
                break;
        }
    }

    public syncMode(): void {
        this.sessionStore.clearTask("STICKER_COLLAGE");
    }
}

