export const CANVAS_RESOLUTION = 400;

export class CanvasPainter {
  private isDrawing = false;
  private lastPoint: { x: number; y: number } | null = null;
  /** The pointer id of the finger/stylus that started the current stroke. */
  private activePointerId: number | null = null;

  constructor(
    private readonly getCanvas: () => HTMLCanvasElement | undefined,
    private readonly getColor: () => string,
    private readonly getBrushSize: () => number,
  ) {}

  public init(): boolean {
    const canvas = this.getCanvas();
    if (!canvas) return false;
    canvas.width = CANVAS_RESOLUTION;
    canvas.height = CANVAS_RESOLUTION;
    const ctx = canvas.getContext("2d");
    if (ctx) {
      ctx.fillStyle = "#ffffff";
      ctx.fillRect(0, 0, CANVAS_RESOLUTION, CANVAS_RESOLUTION);
    }
    return true;
  }

  /** Load an image (data-URL or http URL) onto the canvas as starting content. */
  public loadImage(src: string): void {
    const canvas = this.getCanvas();
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      ctx.fillStyle = "#ffffff";
      ctx.fillRect(0, 0, CANVAS_RESOLUTION, CANVAS_RESOLUTION);
      ctx.drawImage(img, 0, 0, CANVAS_RESOLUTION, CANVAS_RESOLUTION);
    };
    img.src = src;
  }

  public clear(): void {
    const canvas = this.getCanvas();
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (ctx) {
      ctx.fillStyle = "#ffffff";
      ctx.fillRect(0, 0, canvas.width, canvas.height);
    }
  }

  public pointerDown(event: PointerEvent): void {
    event.preventDefault();
    // Only allow one pointer to draw at a time — ignore additional fingers
    if (this.isDrawing) return;

    const canvas = this.getCanvas();
    if (!canvas) return;
    canvas.setPointerCapture(event.pointerId);
    this.isDrawing = true;
    this.activePointerId = event.pointerId;

    const rect = canvas.getBoundingClientRect();
    const scale = CANVAS_RESOLUTION / rect.width;
    this.lastPoint = {
      x: (event.clientX - rect.left) * scale,
      y: (event.clientY - rect.top) * scale,
    };

    const ctx = canvas.getContext("2d");
    if (ctx && this.lastPoint) {
      ctx.fillStyle = this.getColor();
      ctx.beginPath();
      ctx.arc(this.lastPoint.x, this.lastPoint.y, this.getBrushSize() / 2, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  public pointerMove(event: PointerEvent): void {
    if (!this.isDrawing || !this.lastPoint) return;
    event.preventDefault();
    // Ignore events from fingers that didn't start the stroke
    if (event.pointerId !== this.activePointerId) return;
    const canvas = this.getCanvas();
    if (!canvas) return;

    const rect = canvas.getBoundingClientRect();
    const scale = CANVAS_RESOLUTION / rect.width;
    const currentX = (event.clientX - rect.left) * scale;
    const currentY = (event.clientY - rect.top) * scale;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    ctx.strokeStyle = this.getColor();
    ctx.lineWidth = this.getBrushSize();
    ctx.lineCap = "round";
    ctx.lineJoin = "round";
    ctx.beginPath();
    ctx.moveTo(this.lastPoint.x, this.lastPoint.y);
    ctx.lineTo(currentX, currentY);
    ctx.stroke();
    this.lastPoint = { x: currentX, y: currentY };
  }

  public pointerUp(event: PointerEvent): void {
    // Only end the stroke when the original finger lifts
    if (event.pointerId !== this.activePointerId) return;
    this.isDrawing = false;
    this.lastPoint = null;
    this.activePointerId = null;
  }

  public toDataURL(): string | null {
    const canvas = this.getCanvas();
    return canvas ? canvas.toDataURL("image/png") : null;
  }
}

import {signal, computed} from '@angular/core';
import type {
  StickerCollage,
  StickerPack,
  StickerHand,
  StickerCollageBuildingState,
  StickerCollageVotingState,
  StickerCollageResultsState,
  SessionState,
} from '@birthday/shared';
import {WorldStore} from '../core/world.store';
import {GameSessionStore} from '../core/challenge.store';
import {WebSocketService} from '../core/websocket.service';
import {StickerPlayerService} from '../features/game/services/sticker-player.service';
import {
  lobbyPhase,
  buildingPhase,
  votingPhase,
  resultsPhase,
  nextRoundPhase,
  makeSessionState,
} from './mock-data';

class MockWorldStore {
  readonly sessionState = signal<SessionState | null>(makeSessionState(lobbyPhase()));
  readonly lastError = signal<string | null>(null);
  readonly players = computed(() => this.sessionState()?.players ?? {});
  readonly allPlayers = computed(() => Object.values(this.players()));
  readonly leaderboard = computed(() =>
    Object.values(this.players())
      .filter(p => p.name.trim().length > 0)
      .sort((a, b) => b.score - a.score || a.joinedAt - b.joinedAt)
  );
  readonly stickerCollageGameState = computed(() => this.sessionState()?.gameState ?? null);

  setSessionState(state: SessionState) { this.sessionState.set(state); this.lastError.set(null); }
  clearSessionState() { this.sessionState.set(null); }
}

class MockGameSessionStore {
  readonly sessionId = signal<string | null>('mock-session');
  readonly playerId = signal<string | null>('player-1');
  readonly clientId = signal<string | null>('mock-client');
  readonly playerName = signal<string>('Anna');
  readonly currentMode = signal<'LOBBY' | 'STICKER_COLLAGE' | 'IDLE'>('STICKER_COLLAGE');
  readonly feedback = signal<{text: string; type: 'success' | 'error'} | null>(null);

  setSession(id: string) { this.sessionId.set(id); }
  setJoined(args: {sessionId: string; playerId: string; clientId: string}) {
    this.sessionId.set(args.sessionId);
    this.playerId.set(args.playerId);
    this.clientId.set(args.clientId);
  }
  clearTask(nextMode: 'LOBBY' | 'STICKER_COLLAGE' | 'IDLE' = 'IDLE') { this.currentMode.set(nextMode); }
