    const preset = PRESETS[this.animType] ?? PRESETS.opacity;
    gsap.fromTo(elements, preset.from, {
      ...preset.to,
      stagger: this.animStagger,
      delay: this.animDelay,
      onComplete: () => {
        this.isDone = true;
      },
    });
  }
}

