    gsap.set(this.el.nativeElement, PRESETS[this.animType]?.from ?? PRESETS.opacity.from);
    this.group?.register(this);
  }

  public ngAfterViewInit(): void {
    // Delegate to the group only if the group animation hasn't finished yet
