import {Component, signal, computed, ElementRef, ViewChild, OnDestroy, OnInit, AfterViewInit, HostListener} from "@angular/core";
import {CommonModule} from "@angular/common";
import {FormsModule} from "@angular/forms";
import {RouterModule} from "@angular/router";
import {PolygonEditService} from './helper/polygon-edit.service';
import {HitboxPersistenceService} from './helper/hitbox-persistence.service';
import {EditorInteractionHandler} from './helper/editor-interaction.handler';
import {autoDetectHitbox} from './helper/auto-hitbox.util';
import {StickerImgComponent} from '../../shared/sticker-editor/sticker-img/sticker-img.component';
import {SvgComponent} from '../../shared/svg/svg.component';
import {resolveToImgUrl} from '../../shared/sticker-editor/sprite-url.util';

/**
 * Visual hitbox polygon editor for stickers.
 *
 * Thin orchestrator — delegates polygon state to {@link PolygonEditService},
 * persistence to {@link HitboxPersistenceService}, and mouse/keyboard
 * interaction to {@link EditorInteractionHandler}.
 *
 * Route: /hitbox-editor
 */
@Component({
    selector: "app-hitbox-editor",
    standalone: true,
    imports: [CommonModule, FormsModule, RouterModule, StickerImgComponent, SvgComponent],
    templateUrl: "./hitbox-editor.component.html",
    providers: [PolygonEditService, HitboxPersistenceService, EditorInteractionHandler],
})
export class HitboxEditorComponent implements OnInit, AfterViewInit, OnDestroy {
    @ViewChild("editorArea") editorArea!: ElementRef<HTMLDivElement>;

    /**
     * How far beyond the image edge (as a fraction of the image size)
     * points can be placed. 0.05 = 5 % overflow on each side.
     */
    public readonly overflowFraction = 0;

    /** Auto-detect UI state */
    public readonly autoDetecting = signal(false);
    public readonly tolerance = signal(0.02);
    public readonly alphaThreshold = signal(20);

    /** Natural image dimensions — updated when a sticker image loads */
    private readonly imgNatWidth = signal(1);
    private readonly imgNatHeight = signal(1);

    /** Available container dimensions — updated via ResizeObserver */
    private readonly containerWidth = signal(600);
    private readonly containerHeight = signal(400);

    /** Pixel padding derived from fitted image size and overflowFraction */
    public readonly edgePaddingX = computed(() =>
        Math.ceil(this.fittedWidth() * this.overflowFraction));

    public readonly edgePaddingY = computed(() =>
        Math.ceil(this.fittedHeight() * this.overflowFraction));

    /** Fitted image width (fills available space minus overflow margins, preserves aspect ratio) */
    public readonly fittedWidth = computed(() => {
        const aspect = this.imgNatWidth() / this.imgNatHeight();
        const shrink = 1 + this.overflowFraction * 2; // leave room for overflow on each side
        const cw = Math.floor(this.containerWidth() / shrink);
        const ch = Math.floor(this.containerHeight() / shrink);
        if (cw <= 0 || ch <= 0) return 100;
        return cw / ch > aspect ? Math.floor(ch * aspect) : cw;
    });

    /** Fitted image height */
    public readonly fittedHeight = computed(() => {
        const aspect = this.imgNatWidth() / this.imgNatHeight();
        const shrink = 1 + this.overflowFraction * 2;
        const cw = Math.floor(this.containerWidth() / shrink);
        const ch = Math.floor(this.containerHeight() / shrink);
        if (cw <= 0 || ch <= 0) return 100;
        return cw / ch > aspect ? ch : Math.floor(cw / aspect);
    });

    /** Interactive wrapper width (image + overflow padding on each side) */
    public readonly wrapperWidth = computed(() =>
        this.fittedWidth() + this.edgePaddingX() * 2);

    /** Interactive wrapper height (image + overflow padding on each side) */
    public readonly wrapperHeight = computed(() =>
        this.fittedHeight() + this.edgePaddingY() * 2);

    /** SVG points string in pixel coordinates (offset by edge padding) */
    public readonly svgPixelPoints = computed(() => {
        const w = this.fittedWidth();
        const h = this.fittedHeight();
        const px = this.edgePaddingX();
        const py = this.edgePaddingY();
        return this.poly.polygon().map(p => `${p.x * w + px},${p.y * h + py}`).join(" ");
    });

    /**
     * Resolved URL for the editor canvas <img> — needed for naturalWidth/Height.
     * For sprite: URLs this is a blob: URL; for plain paths returned as-is.
     */
    public readonly resolvedDisplayUrl = signal<string>('');
    private _currentDisplayBlob: string | null = null;

    private resizeObserver: ResizeObserver | null = null;

    constructor(
        public readonly poly: PolygonEditService,
        public readonly persistence: HitboxPersistenceService,
        public readonly interaction: EditorInteractionHandler,
    ) {}

    // ── Lifecycle ─────────────────────────────────────────────

    async ngOnInit(): Promise<void> {
        await this.persistence.loadCatalog();
    }

    ngAfterViewInit(): void {
        this.resizeObserver = new ResizeObserver(entries => {
            for (const entry of entries) {
                this.containerWidth.set(Math.floor(entry.contentRect.width));
                this.containerHeight.set(Math.floor(entry.contentRect.height));
            }
        });
        if (this.editorArea?.nativeElement) {
            this.resizeObserver.observe(this.editorArea.nativeElement);
        }
    }

    ngOnDestroy(): void {
        this.resizeObserver?.disconnect();
        this.persistence.destroy();
    }

    // ── Template callbacks ───────────────────────────────────

    public async selectSticker(sticker: import('@birthday/shared').StickerDefinition): Promise<void> {
        this.persistence.selectSticker(sticker);
        // Reset dimensions while loading
        this.imgNatWidth.set(1);
        this.imgNatHeight.set(1);
        // Revoke previous blob if any
        if (this._currentDisplayBlob) {
            URL.revokeObjectURL(this._currentDisplayBlob);
            this._currentDisplayBlob = null;
        }
        // Resolve to a loadable URL. For sprite: URLs we also get the viewBox
        // dimensions directly — no need to wait for onImageLoaded.
        const { url, intrinsicWidth, intrinsicHeight } = await resolveToImgUrl(sticker.imageUrl, 512);
        this._currentDisplayBlob = url;
        if (intrinsicWidth && intrinsicHeight) {
            this.imgNatWidth.set(intrinsicWidth);
            this.imgNatHeight.set(intrinsicHeight);
        }
        this.resolvedDisplayUrl.set(url);
    }

    public onImageLoaded(event: Event): void {
        const img = event.target as HTMLImageElement;
        // Only trust naturalWidth/Height for non-SVG images (PNG/JPEG).
        // For SVG blob URLs the values are unreliable across browsers;
        // we already set the dimensions from the viewBox in selectSticker().
        if (img.naturalWidth > 0 && img.naturalHeight > 0 && !this._currentDisplayBlob) {
            this.imgNatWidth.set(img.naturalWidth);
            this.imgNatHeight.set(img.naturalHeight);
        }
    }

    public async runAutoDetect(): Promise<void> {
        const sticker = this.persistence.selectedSticker();
        if (!sticker) {
          return;
        }
        this.autoDetecting.set(true);
        try {
            const result = await autoDetectHitbox(sticker.imageUrl, this.tolerance(), this.alphaThreshold());
            if (result.length >= 3) {
                this.poly.load(result);
            }
        } finally {
            this.autoDetecting.set(false);
        }
    }

    @HostListener("window:keydown", ["$event"])
    onKeyDown(event: KeyboardEvent): void {
        if (this.interaction.onKeyDown(event)) {
            event.preventDefault();
        }
    }
}

import {Component, computed, input} from '@angular/core';

/**
 * Design-tier for icons.
 *
 * The tier controls which SVG symbol variant is loaded from the sprite,
 * because icons at different sizes need different levels of detail:
 *
 *  - **sm**  (≤ 16 px) — thick strokes, minimal detail  → `#icon-{name}-sm`
 *  - **md**  (20–36 px) — balanced detail                → `#icon-{name}-md`
 *  - **lg**  (40–64 px) — full detail, thin strokes      → `#icon-{name}-lg`
 *
 * The graphic designer receives the tier suffix as part of the SVG filename
 * (e.g. `icon-star-sm.svg`, `icon-star-lg.svg`) so they know exactly which
 * level of detail to target.
 *
 * If only one variant exists in the sprite the component falls back:
 *   lg → md → sm → bare name (no suffix).
 * This fallback is purely convention — the sprite build script does NOT
 * generate variants automatically; each variant is a separate source SVG.
 */
export type IconSize = 'sm' | 'md' | 'lg' | 'xl';

/** Maps design-tier to a fixed pixel dimension. */
const SIZE_PX: Record<IconSize, number> = {
    sm: 20,
    md: 40,
    lg: 70,
    xl: 120,
};

const SPRITE = 'assets/sprite.svg';

/**
 * Renders an icon from the SVG sprite at a predefined design-tier size.
 *
 * Usage:
 *   <app-icon name="star" size="sm"/>          → 16 × 16,  loads #icon-star-sm
 *   <app-icon name="star" size="md"/>          → 24 × 24,  loads #icon-star-md
 *   <app-icon name="star" size="lg"/>          → 40 × 40,  loads #icon-star-lg
 *   <app-icon name="star"/>                    → 24 × 24   (default md)
 *
 * The host element is sized automatically — no extra w-* / h-* classes needed.
 * Tailwind color utilities (text-red-500 etc.) work via currentColor.
 */
@Component({
    selector: 'app-icon',
    standalone: true,
    template: `
        <svg [attr.width]="px()" [attr.height]="px()"
             aria-hidden="true" focusable="false"
             style="display:block;overflow:hidden;"
             [style.color]="outlineColor()">
            <use [attr.href]="href()"/>
        </svg>
    `,
    host: {
        style: 'display:inline-flex;align-items:center;justify-content:center;line-height:0;',
        '[style.width.px]': 'px()',
        '[style.height.px]': 'px()',
    },
})
export class IconComponent {
    /** Icon name without the `icon-` prefix and without the size suffix.  E.g. `"star"`. */
    readonly name = input.required<string>();

    /** Design tier — controls which sprite symbol variant is loaded **and** the rendered size. */
    readonly size = input<IconSize>('md');

    /** Stroke/outline color. Overrides Tailwind text-* classes when set. */
    readonly outlineColor = input<string>("#000000");

    /** Resolved pixel size. */
    readonly px = computed(() => SIZE_PX[this.size()]);

    /** Full sprite href including the size-tier suffix. */
    readonly href = computed(() => `${SPRITE}#icon-${this.name()}-${this.size()}`);
}

import {CommonModule} from "@angular/common";
import {Component, ElementRef, OnInit, QueryList, ViewChildren, signal} from "@angular/core";
import {ActivatedRoute, Router} from "@angular/router";
import {HttpClient} from "@angular/common/http";
import {firstValueFrom} from "rxjs";
import {ApiService} from '../../../core/api.service';
import {AnimOnInitDirective, AnimPresenceDirective} from '../../shared/animations/anim-on-init.directive';

@Component({
  selector: "app-landing",
  standalone: true,
  imports: [CommonModule, AnimOnInitDirective, AnimPresenceDirective],
  templateUrl: "./landing.component.html",
})
export class LandingComponent implements OnInit {
  public readonly digitSlots = [0, 1, 2, 3] as const;
  public readonly codeDigits = signal<string[]>(["", "", "", ""]);
  public readonly sessionCode = signal<string>("");
  public readonly sessionCodeShakeActive = signal<boolean>(false);
  public readonly passwordShakeActive = signal<boolean>(false);

  // Board password dialog state
  public readonly showPasswordDialog = signal<boolean>(false);
  public readonly boardPassword = signal<string>("");
  public readonly passwordLoading = signal<boolean>(false);
  public readonly sessionJoinLoading = signal<boolean>(false);

  @ViewChildren("codeInput")
  private readonly codeInputs?: QueryList<ElementRef<HTMLInputElement>>;

  private boardAlreadyAuthed = false;
  private sessionShakeTimeout: ReturnType<typeof setTimeout> | null = null;
  private passwordShakeTimeout: ReturnType<typeof setTimeout> | null = null;

  public constructor(
    private readonly route: ActivatedRoute,
    private readonly router: Router,
    private readonly http: HttpClient,
    private readonly apiService: ApiService,
  ) {}

  public ngOnInit(): void {
    const routeCode = this.route.snapshot.paramMap.get("sessionCode");
    if (routeCode) {
      const normalized = this.normalizeSessionCode(routeCode);
      this.setCodeFromString(normalized);
      void this.verifyAndNavigateToPlayer(normalized);
      return;
    }

    const error = this.route.snapshot.queryParamMap.get("error");
    if (error === "invalid-session") {
      this.triggerSessionCodeShake();
      void this.router.navigate([], {
        relativeTo: this.route,
        queryParams: {error: null},
        queryParamsHandling: "merge",
        replaceUrl: true,
      });
    }

    void this.checkBoardAuth();
  }

  private async checkBoardAuth(): Promise<void> {
    try {
      await firstValueFrom(this.http.get("/api/auth/board-status"));
      this.boardAlreadyAuthed = true;
    } catch {
      this.boardAlreadyAuthed = false;
    }
  }

  public onCodeDigitInput(index: number, event: Event): void {
    const input = event.target as HTMLInputElement;
    const digit = this.normalizeSessionCode(input.value).slice(-1);
    this.updateDigit(index, digit);

    if (digit && index < this.digitSlots.length - 1) {
      this.focusCodeInput(index + 1);
    }
  }

  public onCodeDigitKeydown(index: number, event: KeyboardEvent): void {
    if (event.key === "Backspace") {
      event.preventDefault();
      const digits = [...this.codeDigits()];
      if (digits[index]) {
        digits[index] = "";
        this.syncCodeState(digits);
        return;
      }
      if (index > 0) {
        digits[index - 1] = "";
        this.syncCodeState(digits);
        this.focusCodeInput(index - 1);
      }
      return;
    }

    if (event.key === "ArrowLeft" && index > 0) {
      event.preventDefault();
      this.focusCodeInput(index - 1);
      return;
    }

    if (event.key === "ArrowRight" && index < this.digitSlots.length - 1) {
      event.preventDefault();
      this.focusCodeInput(index + 1);
      return;
    }

    if (event.key === "Enter") {
      this.joinSession();
      return;
    }

    if (event.key.length === 1 && !/[0-9]/.test(event.key)) {
      event.preventDefault();
    }
  }

  public onCodePaste(index: number, event: ClipboardEvent): void {
    const pastedText = event.clipboardData?.getData("text") ?? "";
    const normalized = this.normalizeSessionCode(pastedText);
    if (!normalized) return;

    event.preventDefault();
    const digits = [...this.codeDigits()];
    for (let i = index; i < this.digitSlots.length; i++) {
      digits[i] = normalized[i - index] ?? "";
    }
    this.syncCodeState(digits);

    const nextEmptyIndex = digits.findIndex((digit) => !digit);
    this.focusCodeInput(nextEmptyIndex === -1 ? this.digitSlots.length - 1 : nextEmptyIndex);
  }

  public async joinSession(): Promise<void> {
    const code = this.sessionCode();
    await this.verifyAndNavigateToPlayer(code);
  }

  public async goToBoard(): Promise<void> {
    if (this.boardAlreadyAuthed) {
      void this.router.navigate(["/board"]);
      return;
    }
    this.boardPassword.set("");
    this.showPasswordDialog.set(true);
  }

  public async submitPassword(): Promise<void> {
    this.passwordLoading.set(true);
    try {
      await firstValueFrom(
        this.http.post("/api/auth/board-login", {password: this.boardPassword()}),
      );
      this.showPasswordDialog.set(false);
      void this.router.navigate(["/board"]);
    } catch {
      this.triggerPasswordShake();
    } finally {
      this.passwordLoading.set(false);
    }
  }

  public cancelPasswordDialog(): void {
    this.showPasswordDialog.set(false);
  }

  private updateDigit(index: number, digit: string): void {
    const digits = [...this.codeDigits()];
    digits[index] = digit;
    this.syncCodeState(digits);
  }

  private syncCodeState(digits: string[]): void {
    this.codeDigits.set(digits);
    this.sessionCode.set(digits.join(""));
  }

  private setCodeFromString(code: string): void {
    const normalized = this.normalizeSessionCode(code);
    const digits = ["", "", "", ""];
    for (let i = 0; i < digits.length; i++) {
      digits[i] = normalized[i] ?? "";
    }
    this.syncCodeState(digits);
  }

  private async verifyAndNavigateToPlayer(code: string): Promise<void> {
    const normalized = this.normalizeSessionCode(code);
    if (normalized.length < 4 || this.sessionJoinLoading()) {
      if (normalized.length < 4) this.triggerSessionCodeShake();
      return;
    }

    this.sessionJoinLoading.set(true);
    try {
      const resolved = await this.apiService.resolveSessionByCode(normalized);
      const resolvedCode = this.normalizeSessionCode(resolved.sessionCode ?? normalized);
      this.setCodeFromString(resolvedCode);
      void this.router.navigate(["/player"], {queryParams: {session: resolvedCode}});
    } catch {
      this.triggerSessionCodeShake();
    } finally {
      this.sessionJoinLoading.set(false);
    }
  }

  private focusCodeInput(index: number): void {
    const input = this.codeInputs?.get(index)?.nativeElement;
    if (!input) return;
    input.focus();
    input.select();
  }

  private triggerSessionCodeShake(): void {
    if (this.sessionShakeTimeout) clearTimeout(this.sessionShakeTimeout);
    this.sessionCodeShakeActive.set(false);
    setTimeout(() => this.sessionCodeShakeActive.set(true), 0);
    this.sessionShakeTimeout = setTimeout(() => {
      this.sessionCodeShakeActive.set(false);
      this.sessionShakeTimeout = null;
    }, 450);
  }

  private triggerPasswordShake(): void {
    if (this.passwordShakeTimeout) clearTimeout(this.passwordShakeTimeout);
    this.passwordShakeActive.set(false);
    setTimeout(() => this.passwordShakeActive.set(true), 0);
    this.passwordShakeTimeout = setTimeout(() => {
      this.passwordShakeActive.set(false);
      this.passwordShakeTimeout = null;
    }, 450);
  }


  private normalizeSessionCode(rawValue: string): string {
    return rawValue
      .replace(/[^0-9]/g, "")
      .slice(0, 4);
  }
}

import {Component, input, output, signal, ViewChild} from "@angular/core";
import { DrawingCanvasComponent } from '../../../shared/paint-canvas/drawing-canvas.component';
import {AnimOnInitDirective, AnimGroupDirective} from '../../../shared/animations/anim-on-init.directive';
import {SvgComponent} from '../../../shared/svg/svg.component';

@Component({
  selector: "app-lobby-avatar",
  standalone: true,
  imports: [DrawingCanvasComponent, AnimOnInitDirective, AnimGroupDirective, SvgComponent],
  templateUrl: './lobby-avatar.component.html',
  host: {"class": "flex-1 flex flex-col overflow-hidden"},
})
export class LobbyAvatarComponent {
  public readonly playerName = input.required<string>();
  public readonly initialAvatarImage = input<string | null>(null);
  public readonly avatarSubmitted = output<string>();
  public readonly skipped = output<void>();

  public drawMode = signal<"big" | "small" | "erase">("big");

  @ViewChild("drawingCanvas") drawingCanvas!: DrawingCanvasComponent;

  public clear(): void {
    this.drawingCanvas.clear();
  }

  public submit(): void {
    this.drawingCanvas.submit();
  }

  protected selectThinBrush() {
    this.drawMode.set("small");
  }

  protected selectThickBrush() {
    this.drawMode.set("big");
  }

  protected selectEraser() {
    this.drawMode.set("erase");
  }
