@if (box()) {
  @let boundingBox = box()!;
  @let pad = padding()!;
  @let centerX = boundingBox.x + boundingBox.w / 2;
  @let centerY = boundingBox.y + boundingBox.h / 2;
  @let rad = rotation() * Math.PI / 180;
  @let mode = activeMode();

  <!-- Selection rectangle -->
  @let tl = rotatePt(boundingBox.x - pad, boundingBox.y - pad, centerX, centerY, rad);
  @let tr = rotatePt(boundingBox.x + boundingBox.w + pad, boundingBox.y - pad, centerX, centerY, rad);
  @let br = rotatePt(boundingBox.x + boundingBox.w + pad, boundingBox.y + boundingBox.h + pad, centerX, centerY, rad);
  @let bl = rotatePt(boundingBox.x - pad, boundingBox.y + boundingBox.h + pad, centerX, centerY, rad);
  <svg class="absolute inset-0 w-full h-full pointer-events-none overflow-visible" style="z-index:8000;">
    <polygon [attr.points]="svgRect(tl,tr,br,bl)" fill="none" stroke="#374151" stroke-width="2" stroke-dasharray="6 3"/>
  </svg>

  <!-- Center: move icon -->
  <div class="absolute flex items-center justify-center w-11 h-11 select-none pointer-events-none -translate-1/2"
       [style.left.px]="centerX" [style.top.px]="centerY"
       style="z-index:8050;">
    <app-svg name="icon-overlay-move-md" w="40" [color]="LIGHT_PURPLE_SEMI"/>
  </div>

  <!-- NW: Rotate handle -->
  @let nw = rotatePt(boundingBox.x - pad, boundingBox.y - pad, centerX, centerY, rad);
  <div
    class="absolute flex items-center justify-center w-11 h-11 rounded-full border-2 shadow select-none touch-none -translate-1/2 bg-white border-stone-700"
    [style.left.px]="nw.x" [style.top.px]="nw.y"
    style="z-index:8100; cursor:grab; pointer-events:auto;"
    (pointerdown)="onHandleDown($event, 'rotate')">
    <app-svg name="icon-overlay-rotate-md" w="40" [color]="mode === 'rotating' ? DARK_PURPLE :  LIGHT_PURPLE"/>
  </div>

  <!-- NE: Context-menu button -->
  @let ne = rotatePt(boundingBox.x + boundingBox.w + pad, boundingBox.y - pad, centerX, centerY, rad);
  <div
    class="absolute flex items-center justify-center w-11 h-11 rounded-full border-2 shadow select-none touch-none cursor-pointer -translate-1/2 bg-white border-stone-700"
    [style.left.px]="ne.x" [style.top.px]="ne.y"
    style="z-index:8200; pointer-events:auto;"
    title="Optionen"
    (pointerdown)="$event.stopPropagation(); menuToggle.emit()">
    <app-svg name="icon-overlay-menu-md" w="40" [color]="mode === 'menu' ? DARK_PURPLE : LIGHT_PURPLE"/>
  </div>

  <!-- SE: Scale handle -->
  @let scale = rotatePt(boundingBox.x + boundingBox.w + pad, boundingBox.y + boundingBox.h + pad, centerX, centerY, rad);
  <div
    class="absolute flex items-center justify-center w-11 h-11 rounded-full border-2 shadow select-none touch-none -translate-1/2 bg-white border-stone-700"
    [style.left.px]="scale.x" [style.top.px]="scale.y"
    style="z-index:8100; cursor:se-resize; pointer-events:auto;"
    (pointerdown)="onHandleDown($event, 'scale')">
    <app-svg name="icon-overlay-scale-md" w="40" [color]="mode === 'scaling' ? DARK_PURPLE : LIGHT_PURPLE"/>
  </div>

  <!-- Stretch side handles (stretch mode only) -->
  @if (stretchModeVisible()) {
    @for (side of sides(); track side.id) {
      <div
        class="absolute w-11 h-11 flex items-center justify-center bg-stone-800 border-2 border-stone-900 rounded-full shadow select-none touch-none -translate-1/2"
        [style.left.px]="side.x" [style.top.px]="side.y"
        [style.cursor]="side.cursor"
        style="z-index:8100; pointer-events:auto;"
        (pointerdown)="onHandleDown($event, side.id)">
        <app-svg name="icon-ctx-stretch-sm" w="20"/>
      </div>
    }
    <div
      class="absolute pointer-events-none text-xs font-semibold text-stone-700 bg-stone-100 border border-stone-300 rounded px-1.5 py-0.5"
      [style.left.px]="boundingBox.x" [style.top.px]="boundingBox.y - pad - 44"
      style="z-index:8200;">Verformen
    </div>
  }
}

